sparql:
SELECT ?countEUR ?countCZK ?ratio WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cEUR ) AS ?countEUR ) WHERE {
      ?cEUR <http://debitcard.org/schema#currency> "EUR" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cCZK ) AS ?countCZK ) WHERE {
      ?cCZK <http://debitcard.org/schema#currency> "CZK" .
    }
  }
  BIND( ( ?countEUR / ?countCZK ) AS ?ratio )
}

SELECT ( AVG( ?yearSum ) / 12 AS ?avgMonthly ) WHERE {
  {
    SELECT ?cust ( SUM( ?val ) AS ?yearSum ) WHERE {
      ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?date .
      ?cust <http://debitcard.org/schema#segment> "SME" .
      FILTER ( ?date >= "201301" && ?date <= "201312" )
    }
    GROUP BY ?cust
  }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ( ( COALESCE ( ?czkSum , 0 ) - COALESCE ( ?eurSum , 0 ) ) AS ?difference ) ?czkSum ?eurSum WHERE {
  {
    SELECT ( SUM( ?v ) AS ?czkSum ) WHERE {
      ?c rdf:type <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#consumptionValue> ?v ; <http://debitcard.org/schema#forCustomer> ?cust .
      ?cust <http://debitcard.org/schema#currency> "CZK" .
      FILTER ( strstarts( str( ?date ) , "2012" ) )
    }
  }
  {
    SELECT ( SUM( ?v2 ) AS ?eurSum ) WHERE {
      ?c2 rdf:type <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#date> ?date2 ; <http://debitcard.org/schema#consumptionValue> ?v2 ; <http://debitcard.org/schema#forCustomer> ?cust2 .
      ?cust2 <http://debitcard.org/schema#currency> "EUR" .
      FILTER ( strstarts( str( ?date2 ) , "2012" ) )
    }
  }
}
LIMIT 1

SELECT ( ?smeAvg - ?lamAvg AS ?SME_minus_LAM ) ( ?lamAvg - ?kamAvg AS ?LAM_minus_KAM ) ( ?kamAvg - ?smeAvg AS ?KAM_minus_SME ) WHERE {
  {
    SELECT ( SUM( ?total ) / COUNT( ?cust ) AS ?smeAvg ) WHERE {
      {
        SELECT ?cust ?segment ( SUM( ?val ) AS ?total ) WHERE {
          ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?ym .
          ?cust <http://debitcard.org/schema#segment> ?segment .
          FILTER ( ?ym >= "201301" && ?ym <= "201312" )
        }
        GROUP BY ?cust ?segment
      }
      {
        SELECT ?segment ( MIN( ?total ) AS ?minTotal ) WHERE {
          {
            SELECT ?cust ?segment ( SUM( ?val ) AS ?total ) WHERE {
              ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?ym .
              ?cust <http://debitcard.org/schema#segment> ?segment .
              FILTER ( ?ym >= "201301" && ?ym <= "201312" )
            }
            GROUP BY ?cust ?segment
          }
        }
        GROUP BY ?segment
      }
      FILTER ( ?segment = "SME" ) FILTER ( ?total = ?minTotal )
    }
  }
  {
    SELECT ( SUM( ?total ) / COUNT( ?cust ) AS ?lamAvg ) WHERE {
      {
        SELECT ?cust ?segment ( SUM( ?val ) AS ?total ) WHERE {
          ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?ym .
          ?cust <http://debitcard.org/schema#segment> ?segment .
          FILTER ( ?ym >= "201301" && ?ym <= "201312" )
        }
        GROUP BY ?cust ?segment
      }
      {
        SELECT ?segment ( MIN( ?total ) AS ?minTotal ) WHERE {
          {
            SELECT ?cust ?segment ( SUM( ?val ) AS ?total ) WHERE {
              ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?ym .
              ?cust <http://debitcard.org/schema#segment> ?segment .
              FILTER ( ?ym >= "201301" && ?ym <= "201312" )
            }
            GROUP BY ?cust ?segment
          }
        }
        GROUP BY ?segment
      }
      FILTER ( ?segment = "LAM" ) FILTER ( ?total = ?minTotal )
    }
  }
  {
    SELECT ( SUM( ?total ) / COUNT( ?cust ) AS ?kamAvg ) WHERE {
      {
        SELECT ?cust ?segment ( SUM( ?val ) AS ?total ) WHERE {
          ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?ym .
          ?cust <http://debitcard.org/schema#segment> ?segment .
          FILTER ( ?ym >= "201301" && ?ym <= "201312" )
        }
        GROUP BY ?cust ?segment
      }
      {
        SELECT ?segment ( MIN( ?total ) AS ?minTotal ) WHERE {
          {
            SELECT ?cust ?segment ( SUM( ?val ) AS ?total ) WHERE {
              ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?ym .
              ?cust <http://debitcard.org/schema#segment> ?segment .
              FILTER ( ?ym >= "201301" && ?ym <= "201312" )
            }
            GROUP BY ?cust ?segment
          }
        }
        GROUP BY ?segment
      }
      FILTER ( ?segment = "KAM" ) FILTER ( ?total = ?minTotal )
    }
  }
}

SELECT ?segment ?sum2012 ?sum2013 ( ?sum2013 - ?sum2012 AS ?increase ) ( IF( ?sum2013 = 0 , 0 , ( ( ?sum2013 - ?sum2012 ) / ?sum2013 ) * 100 ) AS ?pctIncrease ) WHERE {
  {
    SELECT ?segment ( SUM( IF( STRSTARTS( STR( ?date ) , "2012" ) , ?totalPrice , 0 ) ) AS ?sum2012 ) ( SUM( IF( STRSTARTS( STR( ?date ) , "2013" ) , ?totalPrice , 0 ) ) AS ?sum2013 ) WHERE {
      VALUES ?segment {
        "SME" "LAM" "KAM"
      }
      ?tx a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#totalPrice> ?totalPrice ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#madeBy> ?cust .
      ?cust <http://debitcard.org/schema#segment> ?segment ; <http://debitcard.org/schema#currency> "EUR" .
    }
    GROUP BY ?segment
  }
}
ORDER BY DESC ( ?pctIncrease )

SELECT ?customer ( SUM( ?val ) AS ?total ) WHERE {
  BIND( <http://debitcard.org/customer/6> AS ?customer ) ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#forCustomer> ?customer ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#consumptionValue> ?val .
  FILTER ( ?date >= "201308" && ?date <= "201311" )
}
GROUP BY ?customer

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?countCZE ?countSVK ( ?countCZE - ?countSVK AS ?difference ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?gsC ) AS ?countCZE ) WHERE {
      ?gsC rdf:type <http://debitcard.org/schema#GasStation> .
      ?gsC <http://debitcard.org/schema#segment> "Discount" .
      ?gsC <http://debitcard.org/schema#country> "CZE" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?gsS ) AS ?countSVK ) WHERE {
      ?gsS rdf:type <http://debitcard.org/schema#GasStation> .
      ?gsS <http://debitcard.org/schema#segment> "Discount" .
      ?gsS <http://debitcard.org/schema#country> "SVK" .
    }
  }
}

SELECT ?czkCount ?eurCount ( ?czkCount - ?eurCount AS ?difference ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?czkCount ) WHERE {
      ?cust <http://debitcard.org/schema#segment> "SME" ; <http://debitcard.org/schema#currency> "CZK" .
      FILTER ( STRSTARTS( STR( ?cust ) , "http://debitcard.org/customer/" ) )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cust2 ) AS ?eurCount ) WHERE {
      ?cust2 <http://debitcard.org/schema#segment> "SME" ; <http://debitcard.org/schema#currency> "EUR" .
      FILTER ( STRSTARTS( STR( ?cust2 ) , "http://debitcard.org/customer/" ) )
    }
  }
}

SELECT ?totalLAM ?aboveLAM ?percent WHERE {
  {
    SELECT ( COUNT( ?c ) AS ?totalLAM ) WHERE {
      ?c <http://debitcard.org/schema#segment> "LAM" .
    }
  }
  {
    SELECT ( COUNT( ?cust ) AS ?aboveLAM ) WHERE {
      {
        SELECT ?cust ( SUM( ?val ) AS ?sumCons ) WHERE {
          ?cons <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#forCustomer> ?cust .
          ?cust <http://debitcard.org/schema#segment> "LAM" .
        }
        GROUP BY ?cust
      }
      FILTER ( ?sumCons > 46.73 )
    }
  }
  BIND( ( ?aboveLAM * 100 ) / ?totalLAM AS ?percent )
}

SELECT ( ?pct AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?countTotal ) WHERE {
      ?cons <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#forCustomer> ?cust .
      FILTER ( STR( ?date ) = "201202" )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cust2 ) AS ?countAbove ) WHERE {
      ?cons2 <http://debitcard.org/schema#date> ?date2 ; <http://debitcard.org/schema#forCustomer> ?cust2 ; <http://debitcard.org/schema#consumptionValue> ?val2 .
      FILTER ( STR( ?date2 ) = "201202" ) FILTER ( ?val2 > 528.3 )
    }
  }
  BIND( ( 100.0 * ?countAbove ) / ?countTotal AS ?pct )
}

SELECT ?month ?date ?consumptionValue WHERE {
  ?month <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#consumptionValue> ?consumptionValue .
  FILTER ( STRSTARTS( STR( ?date ) , "2012" ) )
}
ORDER BY DESC ( ?consumptionValue )
LIMIT 1

SELECT DISTINCT ?product ?productDesc WHERE {
  ?tx a <http://debitcard.org/schema#Transaction> .
  ?tx <http://debitcard.org/schema#date> ?date .
  FILTER ( STRSTARTS( str( ?date ) , "2013-09" ) ) .
  ?tx <http://debitcard.org/schema#includesProduct> ?product .
  OPTIONAL {
    ?product <http://debitcard.org/schema#productDescription> ?productDesc .
  }
}
ORDER BY ?product

SELECT DISTINCT ?country WHERE {
  ?tx a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#atStation> ?station .
  ?station <http://debitcard.org/schema#country> ?country .
  FILTER ( SUBSTR( STR( ?date ) , 1 , 7 ) = "2013-06" )
}
ORDER BY ?country

SELECT ( COUNT( DISTINCT ?cust ) AS ?numCustomers ) WHERE {
  ?cust <http://debitcard.org/schema#currency> "EUR" .
  ?cons <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val .
  FILTER ( ?val > 1000 )
}

PREFIX dcs: <http://debitcard.org/schema#>
SELECT DISTINCT ?product ?productDescription WHERE {
  ?txn dcs:includesProduct ?product ;
       dcs:atStation ?station .
  ?station a dcs:GasStation ;
           dcs:country "CZE" .
  ?product dcs:productDescription ?productDescription .
}

SELECT DISTINCT ?time WHERE {
  ?t a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#atStation> ?station ; <http://debitcard.org/schema#time> ?time .
  ?station <http://debitcard.org/schema#chainID> 11 .
}
ORDER BY ?time

SELECT DISTINCT ?currency WHERE {
  ?txn a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#time> ?time ; <http://debitcard.org/schema#madeBy> ?cust .
  FILTER ( STR( ?date ) = "2012-08-24" && STR( ?time ) = "16:25:00" ) ?cust <http://debitcard.org/schema#currency> ?currency .
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?tx ?customer ?segment WHERE {
  ?tx a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#date> "2012-08-23" ^^ xsd:date ; <http://debitcard.org/schema#time> "21:20:00" .
  OPTIONAL {
    ?tx <http://debitcard.org/schema#madeBy> ?customer .
  }
  OPTIONAL {
    ?tx <http://debitcard.org/schema#forCustomer> ?customer .
  }
  OPTIONAL {
    ?tx <http://debitcard.org/schema#cardUsed> ?card .
    ?card <http://debitcard.org/schema#owner> ?customer .
  }
  OPTIONAL {
    ?customer <http://debitcard.org/schema#segment> ?segment .
  }
}
LIMIT 50

SELECT ( COUNT( ?tx ) AS ?count ) WHERE {
  ?tx a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#date> "2012-08-26" ; <http://debitcard.org/schema#time> ?time ; <http://debitcard.org/schema#atStation> ?station .
  ?station <http://debitcard.org/schema#country> "CZE" .
  FILTER ( ?time >= "08:00:00" && ?time <= "09:00:00" )
}

SELECT DISTINCT ?cust ?country WHERE {
  ?tx <http://debitcard.org/schema#date> ?date .
  FILTER ( STRSTARTS( STR( ?date ) , "2012-08-24" ) ) .
  {
    ?tx <http://debitcard.org/schema#pricePerUnit> ?val .
    FILTER ( CONTAINS( STR( ?val ) , "548.4" ) )
  } UNION {
    ?tx <http://debitcard.org/schema#totalPrice> ?val .
    FILTER ( CONTAINS( STR( ?val ) , "548.4" ) )
  } UNION {
    ?tx <http://debitcard.org/schema#consumptionValue> ?val .
    FILTER ( CONTAINS( STR( ?val ) , "548.4" ) )
  }
  ?tx <http://debitcard.org/schema#madeBy> ?cust .
  OPTIONAL {
    ?cust <http://debitcard.org/schema#country> ?country .
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?eurCustomers ?totalCustomers ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?totalCustomers ) WHERE {
      ?cust a <http://debitcard.org/schema#Customer> .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cust2 ) AS ?eurCustomers ) WHERE {
      ?txn a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#date> "2012-08-25" ^^ xsd:date ; <http://debitcard.org/schema#currency> "EUR" .
      ?txn ?p ?cust2 .
      FILTER ( ?p IN ( <http://debitcard.org/schema#forCustomer> , <http://debitcard.org/schema#madeBy> , <http://debitcard.org/schema#cardUsed> ) )
    }
  }
  BIND( ( ?eurCustomers * 100.0 ) / ?totalCustomers AS ?percentage )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?cust ?custLabel ?cons2012 ?cons2013 ?decreaseRate WHERE {
  ?tx <http://debitcard.org/schema#date> "2012-08-25" ^^ xsd:date ; <http://debitcard.org/schema#pricePerUnit> 634.8 ; <http://debitcard.org/schema#madeBy> ?cust .
  OPTIONAL {
    ?cust rdfs:label ?custLabel
  }
  {
    SELECT ?cust ( SUM( IF( STRSTARTS( STR( ?date ) , "2012" ) , ?val , 0 ) ) AS ?cons2012 ) ( SUM( IF( STRSTARTS( STR( ?date ) , "2013" ) , ?val , 0 ) ) AS ?cons2013 ) WHERE {
      ?consumption <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#consumptionValue> ?val .
    }
    GROUP BY ?cust
  }
  BIND( IF( ?cons2012 != 0 , ( ?cons2012 - ?cons2013 ) / ?cons2012 , 0 ) AS ?decreaseRate )
}

SELECT ( COUNT( ?gs ) AS ?total_gasstations ) ( SUM( IF( STR( ?seg ) = "Premium" , 1 , 0 ) ) AS ?premium_gasstations ) ( ( 100.0 * SUM( IF( STR( ?seg ) = "Premium" , 1 , 0 ) ) / COUNT( ?gs ) ) AS ?percentage ) WHERE {
  ?gs a <http://debitcard.org/schema#GasStation> .
  ?gs <http://debitcard.org/schema#country> "SVK" .
  OPTIONAL {
    ?gs <http://debitcard.org/schema#segment> ?seg .
  }
}

SELECT ?customer ( SUM( ?price ) AS ?totalSpent ) ( SUM( IF( STRSTARTS( STR( ?date ) , "2012-01" ) , ?price , 0 ) ) AS ?spent201201 ) WHERE {
  BIND( <http://debitcard.org/customer/38508> AS ?customer ) .
  ?t a <http://debitcard.org/schema#Transaction> ; <http://debitcard.org/schema#madeBy> ?customer ; <http://debitcard.org/schema#atStation> ?station ; <http://debitcard.org/schema#totalPrice> ?price .
  OPTIONAL {
    ?t <http://debitcard.org/schema#date> ?date .
  }
}
GROUP BY ?customer

SELECT ?customer ( SUM( ?tp ) AS ?total_spent ) ( SUM( ?amt ) AS ?total_amount ) ( ( SUM( ?tp ) / SUM( ?amt ) ) AS ?avg_price_per_item ) ?currency WHERE {
  ?tran <http://debitcard.org/schema#totalPrice> ?tp ; <http://debitcard.org/schema#amount> ?amt ; <http://debitcard.org/schema#madeBy> ?customer .
  OPTIONAL {
    ?customer <http://debitcard.org/schema#currency> ?currency .
  }
}
GROUP BY ?customer ?currency
ORDER BY DESC ( SUM( ?tp ) )
LIMIT 1

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?member ?major ?major_name WHERE {
  ?member a sclub:Member ; sclub:firstName "Angela" ; sclub:lastName "Sanders" ; sclub:hasMajor ?major .
  ?major sclub:majorName ?major_name .
  OPTIONAL {
    ?major rdfs:label ?major_label
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
SELECT ( COUNT( DISTINCT ?member ) AS ?count ) WHERE {
  <http://studentclub.org/event/rec2N69DMcrqN9PJC> sclub:attendedBy ?member .
  ?member sclub:tShirtSize "Medium" .
}

PREFIX sclub: <http://studentclub.org/schema#>
SELECT ( COUNT( ?event ) AS ?meetingCount ) WHERE {
  {
    SELECT ?event WHERE {
      ?event a sclub:Event .
      ?event sclub:eventType ?etype .
      FILTER ( str( ?etype ) = "Meeting" ) ?event sclub:attendedBy ?member .
    }
    GROUP BY ?event
    HAVING ( COUNT( DISTINCT ?member ) > 10 )
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
SELECT ?event ?eventName ( COUNT( DISTINCT ?attendee ) AS ?attCount ) WHERE {
  ?event sclub:attendedBy ?attendee .
  OPTIONAL {
    ?event sclub:eventName ?eventName
  }
  FILTER NOT EXISTS {
    ?event sclub:eventType ?etype2 .
    FILTER ( CONTAINS( LCASE( STR( ?etype2 ) ) , "fund" ) )
  }
}
GROUP BY ?event ?eventName
HAVING ( COUNT( DISTINCT ?attendee ) > 20 )
ORDER BY DESC ( ?attCount )

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?member ( SUM( xsd:decimal ( ?amount ) ) AS ?totalAmount ) ( SAMPLE( ?memberLabel ) AS ?label ) WHERE {
  ?income sclub:amountReceived ?amount .
  ?income sclub:receivedBy ?member .
  ?member sclub:holdsPosition "Vice President" .
  OPTIONAL {
    ?member rdfs:label ?memberLabel
  }
}
GROUP BY ?member

PREFIX sclub: <http://studentclub.org/schema#>
SELECT ?member ?firstName ?lastName WHERE {
  ?member sclub:firstName ?firstName ; sclub:lastName ?lastName ; sclub:livesIn ?zip .
  ?zip sclub:locatedInState "Illinois" .
}
ORDER BY ?lastName ?firstName

PREFIX sclub: <http://studentclub.org/schema#>
ASK WHERE {
  FILTER NOT EXISTS {
    ?expense sclub:forEvent <http://studentclub.org/event/recggMW2eyCYceNcy> .
    FILTER NOT EXISTS {
      ?expense sclub:isApproved true
    }
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sum2019 ?sum2020 ( ?sum2019 - ?sum2020 AS ?difference ) WHERE {
  {
    SELECT ( SUM( xsd:decimal ( ?amt ) ) AS ?sum2019 ) WHERE {
      ?budget sclub:amountSpent ?amt ; sclub:forEvent ?event .
      ?event sclub:eventDate ?date .
      FILTER ( STRSTARTS( STR( ?date ) , "2019" ) )
    }
  }
  {
    SELECT ( SUM( xsd:decimal ( ?amt2 ) ) AS ?sum2020 ) WHERE {
      ?budget2 sclub:amountSpent ?amt2 ; sclub:forEvent ?event2 .
      ?event2 sclub:eventDate ?date2 .
      FILTER ( STRSTARTS( STR( ?date2 ) , "2020" ) )
    }
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
SELECT DISTINCT ?income ?incomeNotes ?notes WHERE {
  ?income sclub:incomeSource ?source .
  ?income sclub:incomeDate ?d .
  FILTER ( lcase( str( ?source ) ) = "fundraising" ) FILTER ( str( ?d ) = "2019-09-14" ) OPTIONAL {
    ?income sclub:incomeNotes ?incomeNotes .
  }
  OPTIONAL {
    ?income sclub:notes ?notes .
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?member ?phone ?label WHERE {
  ?member a sclub:Member ; sclub:firstName "Carlo" ; sclub:lastName "Jacobs" .
  OPTIONAL {
    ?member sclub:phoneNumber ?phone .
  }
  OPTIONAL {
    ?member rdfs:label ?label .
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?event ?eventLabel ?status WHERE {
  ?expense sclub:expenseDescription "Post Cards, Posters" .
  ?expense sclub:expenseDate "2019-08-20" ^^ xsd:date .
  ?expense sclub:linkedToBudget ?budget .
  ?budget sclub:forEvent ?event .
  OPTIONAL {
    ?event sclub:eventStatus ?status
  }
  OPTIONAL {
    ?event rdfs:label ?eventLabel
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?member ?major ?memberLabel ?majorLabel WHERE {
  BIND( <http://studentclub.org/member/recZN8afUWlE5fZHG> AS ?member ) ?member sclub:hasMajor ?major .
  OPTIONAL {
    ?member rdfs:label ?memberLabel .
  }
  OPTIONAL {
    ?major rdfs:label ?majorLabel .
  }
}

PREFIX sclub: <http://studentclub.org/schema#>
SELECT ( COUNT( DISTINCT ?member ) AS ?count ) ( GROUP_CONCAT( DISTINCT STR( ?member ) ; separator = ", " ) AS ?members ) WHERE {
  ?member sclub:hasMajor <http://studentclub.org/major/recxK3MHQFbR9J5uO> .
  ?member sclub:tShirtSize ?size .
  FILTER ( LCASE( STR( ?size ) ) = "medium" )
}

PREFIX sclub: <http://studentclub.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?member ?memberLabel ?major ?majorLabel ?department ?departmentLabel WHERE {
