PREFIX throm: <http://thrombosis.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?in_count ?out_count ?ratio ?percent_deviation ?larger WHERE {
  {
    SELECT ( COUNT( DISTINCT ?p ) AS ?in_count ) WHERE {
      ?p throm:hasSex "Male" .
      ?p throm:admissionType "+" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?q ) AS ?out_count ) WHERE {
      ?q throm:hasSex "Male" .
      ?q throm:admissionType "-" .
    }
  }
  BIND( IF( xsd:integer ( ?out_count ) > 0 , xsd:decimal ( ?in_count ) / xsd:decimal ( ?out_count ) , 0 ) AS ?ratio ) BIND( IF( xsd:integer ( ?out_count ) > 0 , ( ( xsd:decimal ( ?in_count ) - xsd:decimal ( ?out_count ) ) / xsd:decimal ( ?out_count ) ) * 100 , 0 ) AS ?percent_deviation ) BIND( IF( xsd:integer ( ?in_count ) > xsd:integer ( ?out_count ) , "inpatient" , IF( xsd:integer ( ?in_count ) < xsd:integer ( ?out_count ) , "outpatient" , "equal" ) ) AS ?larger )
}

