PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?patient ?nov_sum ?dec_sum ( ( xsd:decimal ( ?nov_sum ) - xsd:decimal ( ?dec_sum ) ) / xsd:decimal ( ?dec_sum ) AS ?decrease_rate ) WHERE {
  {
    SELECT ?patient ( SUM( ?tcho ) AS ?nov_sum ) WHERE {
