  BIND( YEAR( ?mindate ) AS ?minYear ) BIND( MONTH( ?mindate ) AS ?minMonth ) ?race <http://formula1.org/schema#raceDate> ?date .
  FILTER ( YEAR( ?date ) = ?minYear && MONTH( ?date ) = ?minMonth ) OPTIONAL {
