      ?l2 a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#lapMilliseconds> ?ms2 .
    }
  }
  ?lap a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#lapMilliseconds> ?ms ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?race .
  ?driver rdfs:label ?driverLabel .
  OPTIONAL {
    ?race <http://formula1.org/schema#raceName> ?raceName
  }
  FILTER ( ?ms = ?minMs ) BIND( REPLACE( STR( ?driverLabel ) , " [^ ]+$" , "" ) AS ?forename ) BIND( REPLACE( STR( ?driverLabel ) , "^.* " , "" ) AS ?surname )
}
ORDER BY ?lap

SELECT ?driver ?race ( AVG( ?ms ) AS ?avgMs ) WHERE {
  ?lap a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#forRace> <http://formula1.org/race/2> ; <http://formula1.org/schema#byDriver> <http://formula1.org/driver/1> ; <http://formula1.org/schema#lapMilliseconds> ?ms .
  BIND( <http://formula1.org/driver/1> AS ?driver ) BIND( <http://formula1.org/race/2> AS ?race )
}
GROUP BY ?driver ?race

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?driver ( SUM( IF( BOUND( ?pos ) && ( ?pos > 1 ) , 1 , 0 ) ) AS ?numNotFirst ) ( COUNT( ?r ) AS ?numTotal ) ( ( SUM( IF( BOUND( ?pos ) && ( ?pos > 1 ) , 1 , 0 ) ) / COUNT( ?r ) ) * 100 AS ?percentage ) WHERE {
  ?r a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?race .
  OPTIONAL {
    ?r <http://formula1.org/schema#positionOrder> ?pos
  }
  ?race <http://formula1.org/schema#raceYear> ?season .
  ?season <http://formula1.org/schema#seasonYear> ?year .
  FILTER ( xsd:integer ( str( ?year ) ) >= 2010 ) FILTER ( ?driver = <http://formula1.org/driver/1> )
}
