PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

# Best-effort query to compute percentage = (last_time - winner_time)/last_time * 100
SELECT ?race ?raceLabel ?winnerResult ?winnerDriver ?winnerTimeStr ?lastResult ?lastDriver ?lastTimeStr ?percent WHERE {
  # identify the race (either label contains Australian and 2008 or raceYear = 2008)
  ?race rdfs:label ?raceLabel .
  FILTER( (CONTAINS(LCASE(STR(?raceLabel)), "australian") && CONTAINS(STR(?raceLabel), "2008")) || ?race <http://formula1.org/schema#raceYear> "2008"^^xsd:gYear )

  # winner (positionOrder = 1) and a result for the last finisher (max positionOrder) must exist
  {
    SELECT ?race ( ?winnerRes AS ?winnerResult ) ( ?winnerDriver AS ?winnerDriver ) ?winnerTimeStr WHERE {
      ?winnerRes <http://formula1.org/schema#forRace> ?race ;
                 <http://formula1.org/schema#positionOrder> 1 .
      OPTIONAL { ?winnerRes <http://formula1.org/schema#raceTime> ?winnerTimeStr }
      OPTIONAL { ?winnerRes <http://formula1.org/schema#finishTime> ?winnerTimeStr }
      ?winnerRes <http://formula1.org/schema#byDriver> ?winnerDriver .
      FILTER(BOUND(?winnerTimeStr))
    } LIMIT 1
  }

  {
    SELECT ?race ( ?lastRes AS ?lastResult ) ( ?lastDriver AS ?lastDriver ) ?lastTimeStr WHERE {
      ?lastRes <http://formula1.org/schema#forRace> ?race ;
               <http://formula1.org/schema#positionOrder> ?pos .
      OPTIONAL { ?lastRes <http://formula1.org/schema#raceTime> ?lastTimeStr }
      OPTIONAL { ?lastRes <http://formula1.org/schema#finishTime> ?lastTimeStr }
      ?lastRes <http://formula1.org/schema#byDriver> ?lastDriver .
      FILTER(BOUND(?lastTimeStr))
    } ORDER BY DESC(xsd:integer(?pos)) LIMIT 1
  }

  # ensure we have the labels and parse time strings of format HH:MM:SS.mmm
  OPTIONAL { ?race rdfs:label ?raceLabel }

  # parse winner time
  BIND(STR(?winnerTimeStr) AS ?wts)
  BIND(STRAFTER(?wts, "") AS ?wtsn)
  BIND(xsd:decimal(STRBEFORE(?wts, ":")) AS ?w_h)
  BIND(STRAFTER(?wts, ":") AS ?w_rest)
  BIND(xsd:decimal(STRBEFORE(?w_rest, ":")) AS ?w_m)
  BIND(STRAFTER(?w_rest, ":") AS ?w_s_str)
  BIND(xsd:decimal(?w_s_str) AS ?w_s)
  BIND((?w_h * 3600) + (?w_m * 60) + ?w_s AS ?winnerSeconds)

  # parse last finisher time
  BIND(STR(?lastTimeStr) AS ?lts)
  BIND(xsd:decimal(STRBEFORE(?lts, ":")) AS ?l_h)
  BIND(STRAFTER(?lts, ":") AS ?l_rest)
  BIND(xsd:decimal(STRBEFORE(?l_rest, ":")) AS ?l_m)
  BIND(STRAFTER(?l_rest, ":") AS ?l_s_str)
  BIND(xsd:decimal(?l_s_str) AS ?l_s)
  BIND((?l_h * 3600) + (?l_m * 60) + ?l_s AS ?lastSeconds)

  # compute incremental (last - winner) and percent
  BIND((?lastSeconds - ?winnerSeconds) AS ?incremental)
  BIND((?incremental / ?lastSeconds) * 100 AS ?percent)
}
LIMIT 1

SELECT ?circuit WHERE {
  ?circuit a f1:Circuit .
  ?circuit f1:locatedIn <http://formula1.org/location/Australia> .
  ?circuit f1:circuitRef ?ref .
  FILTER(LCASE(STR(?ref)) = "adelaide")
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?constructor ?label ( MAX( ?points ) AS ?maxPoints ) WHERE {
  ?cs a <http://formula1.org/schema#ConstructorStanding> ; <http://formula1.org/schema#points> ?points ; <http://formula1.org/schema#byConstructor> ?constructor .
  ?constructor <http://formula1.org/schema#nationality> "British" .
  OPTIONAL {
    ?constructor rdfs:label ?label
  }
}
GROUP BY ?constructor ?label
ORDER BY DESC ( ?maxPoints )

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?constructor ?constructorLabel WHERE {
  ?cr rdf:type <http://formula1.org/schema#ConstructorResult> ; <http://formula1.org/schema#forRace> <http://formula1.org/race/291> ; <http://formula1.org/schema#points> ?points ; <http://formula1.org/schema#byConstructor> ?constructor .
  FILTER ( ?points = 0 ) OPTIONAL {
    ?constructor rdfs:label ?constructorLabel
  }
}
ORDER BY ?constructorLabel

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( COUNT( ?constructor ) AS ?numJapaneseConstructors ) WHERE {
  {
    SELECT ?constructor WHERE {
      ?constructor a <http://formula1.org/schema#Constructor> ; <http://formula1.org/schema#nationality> "Japanese" .
      ?cr a <http://formula1.org/schema#ConstructorResult> ; <http://formula1.org/schema#byConstructor> ?constructor ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#points> ?points .
    }
    GROUP BY ?constructor
    HAVING ( COUNT( DISTINCT ?race ) = 2 && SUM( xsd:decimal ( ?points ) ) = 0 )
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( COUNT( ?r ) AS ?den ) ( SUM( IF( bound( ?finishTime ) , 1 , 0 ) ) AS ?num ) ( ( SUM( IF( bound( ?finishTime ) , 1 , 0 ) ) * 100.0 ) / COUNT( ?r ) AS ?percentage ) WHERE {
  ?r a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?race .
  ?driver <http://formula1.org/schema#nationality> "Japanese" .
  ?race <http://formula1.org/schema#raceYear> ?season .
  ?season <http://formula1.org/schema#seasonYear> ?year .
  OPTIONAL {
    ?r <http://formula1.org/schema#finishTime> ?finishTime .
  }
  FILTER ( ?year >= "2007" ^^ xsd:gYear && ?year <= "2009" ^^ xsd:gYear )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?fastestLapNumber ?fastestLapTime ?race ?raceLabel WHERE {
  ?res <http://formula1.org/schema#byDriver> <http://formula1.org/driver/18> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#fastestLapTime> ?fastestLapTime ; <http://formula1.org/schema#fastestLapNumber> ?fastestLapNumber .
  ?race <http://formula1.org/schema#raceYear> <http://formula1.org/season/2009> .
  OPTIONAL {
    ?race rdfs:label ?raceLabel
  }
}
ORDER BY ?fastestLapTime
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?race ( AVG( xsd:decimal ( ?speed ) ) AS ?avgFastestLapSpeed ) WHERE {
  BIND( <http://formula1.org/race/5> AS ?race ) ?result <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#fastestLapSpeed> ?speed .
}
GROUP BY ?race

SELECT ?num ?den ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?driver ) AS ?num ) WHERE {
      ?result a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#laps> ?laps .
      ?race <http://formula1.org/schema#raceDate> ?rdate .
      ?driver <http://formula1.org/schema#dob> ?dob .
      FILTER ( YEAR( ?rdate ) >= 2000 && YEAR( ?rdate ) <= 2005 ) .
      FILTER ( YEAR( ?dob ) < 1985 && ?laps > 50 ) .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?driver2 ) AS ?den ) WHERE {
      ?res2 a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver2 ; <http://formula1.org/schema#forRace> ?race2 .
      ?race2 <http://formula1.org/schema#raceDate> ?rdate2 .
      FILTER ( YEAR( ?rdate2 ) >= 2000 && YEAR( ?rdate2 ) <= 2005 ) .
    }
  }
  BIND( IF( ?den = 0 , 0 , ( ?num / ?den ) * 100 ) AS ?percentage )
}

SELECT ( COUNT( DISTINCT ?driver ) AS ?count ) WHERE {
  ?lap a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#lapMilliseconds> ?ms .
  ?driver <http://formula1.org/schema#nationality> ?nat .
  FILTER ( ?ms < 120000 ) .
  FILTER ( str( ?nat ) = "French" )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?driver ?driverCode ?label WHERE {
  ?driver a <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#nationality> ?nat ; <http://formula1.org/schema#driverCode> ?driverCode .
  FILTER ( LCASE( STR( ?nat ) ) = "american" ) OPTIONAL {
    ?driver rdfs:label ?label
  }
}
ORDER BY ?driverCode

SELECT ?driver ?driverNumber ?driverCode ?dob ?nat ?dutchCount WHERE {
  {
    SELECT ?driver ?driverNumber ?driverCode ?dob ?nat WHERE {
      ?driver a <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dob ; <http://formula1.org/schema#driverNumber> ?driverNumber .
      OPTIONAL {
        ?driver <http://formula1.org/schema#driverCode> ?driverCode
      }
      OPTIONAL {
        ?driver <http://formula1.org/schema#nationality> ?nat
      }
    }
    ORDER BY DESC ( YEAR( ?dob ) )
    LIMIT 3
  }
  {
    SELECT ( COUNT( ?d ) AS ?dutchCount ) WHERE {
      {
        SELECT ?d WHERE {
          ?d a <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dob2 ; <http://formula1.org/schema#driverNumber> ?num2 .
        }
        ORDER BY DESC ( YEAR( ?dob2 ) )
        LIMIT 3
      }
      ?d <http://formula1.org/schema#nationality> "Dutch" .
    }
  }
}

SELECT ?driver ?driverRef ?dob WHERE {
  {
    SELECT ( MIN( YEAR( ?dob2 ) ) AS ?minYear ) WHERE {
      ?d <http://formula1.org/schema#nationality> "German" .
      ?d <http://formula1.org/schema#dob> ?dob2 .
      FILTER ( STRSTARTS( STR( ?d ) , "http://formula1.org/driver/" ) )
    }
  }
  ?driver <http://formula1.org/schema#nationality> "German" .
  ?driver <http://formula1.org/schema#dob> ?dob .
  FILTER ( STRSTARTS( STR( ?driver ) , "http://formula1.org/driver/" ) ) FILTER ( YEAR( ?dob ) = ?minYear ) OPTIONAL {
    ?driver <http://formula1.org/schema#driverRef> ?driverRef
  }
}

SELECT DISTINCT ?driver ?driverId ?driverCode WHERE {
  ?driver a <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dob ; <http://formula1.org/schema#driverId> ?driverId .
  OPTIONAL {
    ?driver <http://formula1.org/schema#driverCode> ?driverCode
  }
  ?result <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#fastestLapTime> ?fastestLapTime .
  FILTER ( year( ?dob ) = 1971 )
}
ORDER BY ?driverId

SELECT ( COUNT( ?result ) AS ?disqualifiedFinisherCount ) WHERE {
  ?result a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#raceStatus> <http://formula1.org/status/2> ; <http://formula1.org/schema#finishTime> ?finishTime .
  ?race <http://formula1.org/schema#raceId> ?raceId .
  FILTER ( ?raceId > 50 && ?raceId < 100 )
}

SELECT ?circuit ?circuitName ?location ?lat ?lng ( COUNT( DISTINCT ?race ) AS ?times ) WHERE {
  BIND( <http://formula1.org/location/Austria> AS ?location ) ?circuit <http://formula1.org/schema#locatedIn> ?location .
  OPTIONAL {
    ?circuit <http://formula1.org/schema#circuitName> ?circuitName .
  }
  OPTIONAL {
    ?circuit <http://formula1.org/schema#latitude> ?lat .
  }
  OPTIONAL {
    ?circuit <http://formula1.org/schema#longitude> ?lng .
  }
  OPTIONAL {
    ?race <http://formula1.org/schema#heldAtCircuit> ?circuit .
  }
}
GROUP BY ?circuit ?circuitName ?location ?lat ?lng
ORDER BY DESC ( ?times )

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?driver ?driverLabel ?race ?raceLabel ?raceDate ?raceTime ( YEAR( ?raceDate ) AS ?year ) WHERE {
  {
    SELECT ( MAX( ?dob ) AS ?maxDob ) WHERE {
      ?anyDriver a <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dob .
    }
  }
  ?driver a <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dob .
  FILTER ( ?dob = ?maxDob ) {
    SELECT ?driver ( MIN( ?rdate ) AS ?firstRaceDate ) WHERE {
      ?qual a <http://formula1.org/schema#QualifyingSession> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?r .
      ?r <http://formula1.org/schema#raceDate> ?rdate .
    }
    GROUP BY ?driver
  }
  ?race <http://formula1.org/schema#raceDate> ?raceDate ; <http://formula1.org/schema#raceTime> ?raceTime .
  FILTER ( ?raceDate = ?firstRaceDate ) OPTIONAL {
    ?driver rdfs:label ?driverLabel .
  }
  OPTIONAL {
    ?race rdfs:label ?raceLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?driver ?label ( SUM( xsd:decimal ( ?duration ) ) / COUNT( ?duration ) AS ?avgDuration ) WHERE {
  ?pit a <http://formula1.org/schema#PitStop> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#duration> ?duration .
  ?driver <http://formula1.org/schema#nationality> "German" ; <http://formula1.org/schema#dob> ?dob .
  OPTIONAL {
    ?driver rdfs:label ?label .
  }
  FILTER ( YEAR( ?dob ) >= 1980 && YEAR( ?dob ) <= 1985 ) FILTER regex( str( ?duration ) , "^[0-9]+(\\.[0-9]+)?$" )
}
GROUP BY ?driver ?label
ORDER BY ?avgDuration
LIMIT 3

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?result ?driver ?driverLabel ?finishTime WHERE {
  ?result a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#forRace> <http://formula1.org/race/24> ; <http://formula1.org/schema#positionOrder> 1 ; <http://formula1.org/schema#byDriver> ?driver .
  OPTIONAL {
    ?result <http://formula1.org/schema#finishTime> ?finishTime .
  }
  OPTIONAL {
    ?driver rdfs:label ?driverLabel .
