}

SELECT ?constructor ?constructorRef ?constructorURL WHERE {
  ?result a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#forRace> <http://formula1.org/race/14> ; <http://formula1.org/schema#positionOrder> 1 ; <http://formula1.org/schema#byConstructor> ?constructor .
  OPTIONAL {
