PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?constructor ?constructorLabel ?nationality ( SUM( ?pts ) AS ?totalPoints ) WHERE {
  ?cr a <http://formula1.org/schema#ConstructorResult> .
  ?cr <http://formula1.org/schema#forRace> ?race .
  ?cr <http://formula1.org/schema#points> ?pts .
  ?cr <http://formula1.org/schema#byConstructor> ?constructor .
  ?race <http://formula1.org/schema#raceName> "Monaco Grand Prix" .
  ?race <http://formula1.org/schema#raceYear> ?season .
  ?season <http://formula1.org/schema#seasonYear> ?year .
  FILTER ( ?year >= "1980" ^^ xsd:gYear && ?year <= "2010" ^^ xsd:gYear ) OPTIONAL {
    ?constructor rdfs:label ?constructorLabel .
  }
  OPTIONAL {
    ?constructor <http://formula1.org/schema#nationality> ?nationality .
