PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?driver ?driverLabel WHERE {
  ?q a <http://formula1.org/schema#QualifyingSession> ; <http://formula1.org/schema#forRace> <http://formula1.org/race/32> ; <http://formula1.org/schema#qualifyingPosition> 1 ; <http://formula1.org/schema#q3> ?q3 ; <http://formula1.org/schema#byDriver> ?driver .
  OPTIONAL {
    ?driver rdfs:label ?driverLabel
  }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?driver ?driverLabel ?dob ?nationality ?firstRace ?firstRaceLabel ?firstRaceName ?firstRaceDate WHERE {
  {
    SELECT ( MAX( ?dobInner ) AS ?maxDob ) WHERE {
      ?dInner rdf:type <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dobInner .
    }
  }
  ?driver rdf:type <http://formula1.org/schema#Driver> ; <http://formula1.org/schema#dob> ?dob ; rdfs:label ?driverLabel .
  FILTER ( ?dob = ?maxDob ) OPTIONAL {
    ?driver <http://formula1.org/schema#nationality> ?nationality .
  }
  {
    SELECT ?driver ( MIN( ?raceDateInner ) AS ?firstRaceDate ) WHERE {
      ?resInner rdf:type <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?raceInner .
      ?raceInner <http://formula1.org/schema#raceDate> ?raceDateInner .
    }
    GROUP BY ?driver
  }
  ?res <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?firstRace .
  ?firstRace <http://formula1.org/schema#raceDate> ?firstRaceDate .
  OPTIONAL {
    ?firstRace rdfs:label ?firstRaceLabel .
  }
  OPTIONAL {
    ?firstRace <http://formula1.org/schema#raceName> ?firstRaceName .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?driver ?driverLabel ( COUNT( ?result ) AS ?accidents ) WHERE {
  ?result a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#raceStatus> <http://formula1.org/status/3> .
  ?race <http://formula1.org/schema#raceName> "Canadian Grand Prix" .
  OPTIONAL {
    ?driver rdfs:label ?driverLabel
  }
}
GROUP BY ?driver ?driverLabel
ORDER BY DESC ( ?accidents )
LIMIT 1

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?driver ?driverLabel ?lap ?lapTime ?ms WHERE {
  {
    SELECT ( MIN( ?ms0 ) AS ?minMs ) WHERE {
      ?lap0 a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#lapMilliseconds> ?ms0 .
    }
  }
  ?lap a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#lapMilliseconds> ?ms ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#lapTime> ?lapTime .
  FILTER ( ?ms = ?minMs ) OPTIONAL {
    ?driver rdfs:label ?driverLabel
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?c ?cLabel ?bestLap ?bestLapLabel ?bestMs ?bestTime ?driver ?driverLabel WHERE {
  ?c a <http://formula1.org/schema#Circuit> ; rdfs:label ?cLabel ; <http://formula1.org/schema#locatedIn> <http://formula1.org/location/Italy> .
  {
    SELECT ?c ( MIN( ?ms ) AS ?bestMs ) WHERE {
      ?race <http://formula1.org/schema#heldAtCircuit> ?c .
      ?lap a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#lapMilliseconds> ?ms .
    }
    GROUP BY ?c
  }
  ?race <http://formula1.org/schema#heldAtCircuit> ?c .
  ?bestLap a <http://formula1.org/schema#LapTime> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#lapMilliseconds> ?bestMs ; rdfs:label ?bestLapLabel .
  OPTIONAL {
    ?bestLap <http://formula1.org/schema#lapTime> ?bestTime .
  }
  OPTIONAL {
    ?bestLap <http://formula1.org/schema#byDriver> ?driver .
    ?driver rdfs:label ?driverLabel .
  }
}
ORDER BY ?cLabel

