  } UNION {
    ?pubMain rdfs:label "Marvel Comics" .
  }
  BIND( STRAFTER( STR( ?pubMain ) , "/publisher/" ) AS ?idMain ) ?hero rdf:type hero:Superhero .
  ?hero hero:publishedBy ?pubRef .
