PREFIX hero: <http://superhero.org/schema#>
SELECT DISTINCT ?publisher ?publisherName WHERE {
  {
    SELECT ( MIN( ?val ) AS ?minVal ) WHERE {
      ?ha hero:forAttribute <http://superhero.org/attribute/3> ; hero:attributeValue ?val .
    }
  }
  ?ha hero:forAttribute <http://superhero.org/attribute/3> ; hero:attributeValue ?val ; hero:ofHero ?hero .
  FILTER ( ?val = ?minVal ) ?hero hero:publishedBy ?publisher .
  BIND( STRAFTER( STR( ?publisher ) , "/publisher/" ) AS ?pid ) BIND( IF( CONTAINS( ?pid , "." ) , STRBEFORE( ?pid , "." ) , ?pid ) AS ?pid_no_dot ) BIND( IRI( CONCAT ( "http://superhero.org/publisher/" , ?pid_no_dot ) ) AS ?pubIRI ) OPTIONAL {
    ?pubIRI hero:publisherName ?publisherName .
  }
}

