PREFIX publisher: <http://superhero.org/publisher#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX hero: <http://superhero.org/schema#>
SELECT ?total ?badCount ?marvelBadCount ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?h ) AS ?total ) WHERE {
      ?h a hero:Superhero .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?hb ) AS ?badCount ) WHERE {
      ?hb a hero:Superhero ; hero:hasAlignment ?a .
      BIND( IRI( REPLACE( str( ?a ) , "\\.0$" , "" ) ) AS ?aBase ) OPTIONAL {
        ?aBase rdfs:label ?aLabel
      }
      OPTIONAL {
        ?aBase hero:alignmentType ?aLabel2
      }
      BIND( COALESCE ( ?aLabel , ?aLabel2 , "" ) AS ?aLabelFinal ) FILTER ( str( ?aLabelFinal ) = "Bad" )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?hm ) AS ?marvelBadCount ) WHERE {
      ?hm a hero:Superhero ; hero:hasAlignment ?a ; hero:publishedBy ?p .
      BIND( IRI( REPLACE( str( ?a ) , "\\.0$" , "" ) ) AS ?aBase ) OPTIONAL {
        ?aBase rdfs:label ?aLabel
      }
      OPTIONAL {
        ?aBase hero:alignmentType ?aLabel2
      }
      BIND( COALESCE ( ?aLabel , ?aLabel2 , "" ) AS ?aLabelFinal ) FILTER ( str( ?aLabelFinal ) = "Bad" ) BIND( IRI( REPLACE( str( ?p ) , "\\.0$" , "" ) ) AS ?pBase ) OPTIONAL {
        ?pBase rdfs:label ?pLabel
      }
      OPTIONAL {
        ?pBase publisher:publisherName ?pName
      }
      BIND( COALESCE ( ?pLabel , ?pName , "" ) AS ?pLabelFinal ) FILTER ( str( ?pLabelFinal ) = "Marvel Comics" )
    }
  }
  BIND( ( xsd:decimal ( ?badCount ) * 100.0 ) / xsd:decimal ( ?total ) AS ?percentage )
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX hero: <http://superhero.org/schema#>
SELECT ?marvelPub ?marvelCount ?dcPub ?dcCount ( ( ?marvelCount - ?dcCount ) AS ?difference ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?h1 ) AS ?marvelCount ) WHERE {
      ?h1 hero:publishedBy ?p1 .
      ?h1 rdf:type hero:Superhero .
      FILTER ( CONTAINS( STR( ?p1 ) , "/publisher/13" ) )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?h2 ) AS ?dcCount ) WHERE {
      ?h2 hero:publishedBy ?p2 .
      ?h2 rdf:type hero:Superhero .
      FILTER ( CONTAINS( STR( ?p2 ) , "/publisher/4" ) )
    }
  }
  BIND( <http://superhero.org/publisher/13> AS ?marvelPub ) BIND( <http://superhero.org/publisher/4> AS ?dcPub )
}

