      }
    }
  }
  BIND( <http://superhero.org/publisher/13> AS ?publisherIRI ) BIND( IF( ?den = 0 , 0 , ( xsd:decimal ( ?num ) / xsd:decimal ( ?den ) * 100 ) ) AS ?percentage )
}

