  }
  {
    SELECT ( COUNT( ?post2 ) AS ?high ) WHERE {
      ?post2 a <http://codecomt.org/schema#Post> ; <http://codecomt.org/schema#creationDate> ?cd2 ; <http://codecomt.org/schema#owner> ?owner .
      BIND( IRI( REPLACE( STR( ?owner ) , "\\.0$" , "" ) ) AS ?user ) ?user <http://codecomt.org/schema#reputation> ?rep .
      BIND( xsd:dateTime ( REPLACE( REPLACE( ?cd2 , " " , "T" ) , "\\.0$" , "" ) ) AS ?dt2 ) FILTER ( year( ?dt2 ) = 2011 ) FILTER ( ?rep > 1000 )
    }
  }
}

