SELECT ?totalUsers ?zeroUpVotesUsers ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?user ) AS ?totalUsers ) WHERE {
      ?comment a <http://codecomt.org/schema#Comment> ; <http://codecomt.org/schema#commentScore> ?score ; <http://codecomt.org/schema#commentedBy> ?user .
      FILTER ( ?score >= 5 && ?score <= 10 )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?user0 ) AS ?zeroUpVotesUsers ) WHERE {
      ?comment0 a <http://codecomt.org/schema#Comment> ; <http://codecomt.org/schema#commentScore> ?score0 ; <http://codecomt.org/schema#commentedBy> ?user0 .
      FILTER ( ?score0 >= 5 && ?score0 <= 10 ) ?user0 <http://codecomt.org/schema#upVotes> ?uv0 .
      FILTER ( ?uv0 = 0 )
    }
  }
  BIND( IF( ?totalUsers > 0 , ( ?zeroUpVotesUsers * 100 ) / ?totalUsers , 0 ) AS ?percentage )
}

