PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?foreign ?card ?foreignText ?foreignName ?cardLabel WHERE {
  ?card <http://cardgames.org/schema#setCode> "CSP" .
  ?foreign a <http://cardgames.org/schema#ForeignCardData> ; <http://cardgames.org/schema#language> "Italian" ; <http://cardgames.org/schema#foreignText> ?foreignText ; <http://cardgames.org/schema#forCard> ?card .
  OPTIONAL {
    ?foreign <http://cardgames.org/schema#foreignName> ?foreignName .
  }
  OPTIONAL {
    ?card rdfs:label ?cardLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?card ?label ?baseName ?foreign ?italianName ?cmc WHERE {
  {
    SELECT ( MAX( ?cmc ) AS ?maxCmc ) WHERE {
      ?c a <http://cardgames.org/schema#Card> ; <http://cardgames.org/schema#setCode> "CSP" ; <http://cardgames.org/schema#convertedManaCost> ?cmc .
    }
  }
  ?card a <http://cardgames.org/schema#Card> ; <http://cardgames.org/schema#setCode> "CSP" ; <http://cardgames.org/schema#convertedManaCost> ?cmc ; rdfs:label ?label .
  FILTER ( ?cmc = ?maxCmc ) BIND( STRBEFORE( ?label , " (" ) AS ?baseName ) ?foreign a <http://cardgames.org/schema#ForeignCardData> ; <http://cardgames.org/schema#language> "Italian" ; <http://cardgames.org/schema#foreignName> ?italianName .
  FILTER ( STR( ?italianName ) = STR( ?baseName ) )
}
ORDER BY ?italianName

SELECT ( ( SUM( IF( ?cmc = 7 , 1 , 0 ) ) * 100.0 ) / COUNT( DISTINCT ?card ) AS ?percentage ) ( SUM( IF( ?cmc = 7 , 1 , 0 ) ) AS ?count7 ) ( COUNT( DISTINCT ?card ) AS ?total ) WHERE {
  ?card a <http://cardgames.org/schema#Card> ; <http://cardgames.org/schema#forSet> <http://cardgames.org/set/CSP> ; <http://cardgames.org/schema#convertedManaCost> ?cmc .
}

PREFIX cg: <http://cardgames.org/schema#>
SELECT ((SUM(IF(BOUND(?ckId) && BOUND(?ckFId), 1, 0)) * 100.0) / COUNT(DISTINCT ?card) AS ?percentage)
WHERE {
  ?card a cg:Card ;
        cg:forSet ?set .
  ?set cg:setName "Coldsnap" .
  OPTIONAL { ?card cg:cardKingdomId ?ckId . }
  OPTIONAL { ?card cg:cardKingdomFoilId ?ckFId . }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?format ?cardIRI ?name WHERE {
  {
    SELECT ?format ( COUNT( ?leg ) AS ?bannedCount ) WHERE {
      ?leg <http://cardgames.org/schema#status> "Banned" .
      ?leg <http://cardgames.org/schema#format> ?format .
    }
    GROUP BY ?format
  }
  {
    SELECT ( MAX( ?cnt ) AS ?maxCount ) WHERE {
      {
        SELECT ?format ( COUNT( ?leg ) AS ?cnt ) WHERE {
          ?leg <http://cardgames.org/schema#status> "Banned" .
          ?leg <http://cardgames.org/schema#format> ?format .
        }
        GROUP BY ?format
      }
    }
  }
  FILTER ( ?bannedCount = ?maxCount ) ?leg2 <http://cardgames.org/schema#status> "Banned" .
  ?leg2 <http://cardgames.org/schema#format> ?format .
  BIND( IRI( CONCAT ( "http://cardgames.org/card/" , STRAFTER( STR( ?leg2 ) , "legality/" ) ) ) AS ?cardIRI ) OPTIONAL {
    ?cardIRI <http://cardgames.org/schema#cardName> ?cardName .
  }
  OPTIONAL {
    ?cardIRI rdfs:label ?rdfsLabel .
  }
  OPTIONAL {
    ?foreign <http://cardgames.org/schema#forCard> ?cardIRI ; <http://cardgames.org/schema#language> "English" ; <http://cardgames.org/schema#foreignName> ?foreignName .
  }
  BIND( COALESCE ( ?cardName , ?rdfsLabel , ?foreignName ) AS ?name )
}
ORDER BY ?format ?name

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?card ?name ?status ?format WHERE {
  ?card <http://cardgames.org/schema#edhrecRank> 1 .
  OPTIONAL {
    ?card rdfs:label ?name
  }
  OPTIONAL {
    ?card <http://cardgames.org/schema#status> ?status
  }
  OPTIONAL {
    ?card <http://cardgames.org/schema#format> ?format
  }
}
ORDER BY ?name

PREFIX cg: <http://cardgames.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?card ?cardLabel ?format WHERE {
  ?card cg:forSet <http://cardgames.org/set/HOU> .
  OPTIONAL { ?card rdfs:label ?cardLabel }
  OPTIONAL {
    ?card cg:cardName ?cn .
    ?leg a cg:Legality ;
         cg:cardName ?cn ;
         cg:format ?format ;
         cg:status "Legal" .
  }
}
ORDER BY ?cardLabel

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?set ?setLabel WHERE {
  ?trK a <http://cardgames.org/schema#SetTranslation> ; <http://cardgames.org/schema#forSet> ?set ; <http://cardgames.org/schema#language> "Korean" .
  ?set rdfs:label ?setLabel .
  FILTER NOT EXISTS {
    ?trJ a <http://cardgames.org/schema#SetTranslation> ; <http://cardgames.org/schema#forSet> ?set ; <http://cardgames.org/schema#language> ?langJ .
    FILTER ( CONTAINS( LCASE( STR( ?langJ ) ) , "japanese" ) )
  }
}
ORDER BY ?setLabel

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?card ?cardLabel ?frameVersion ?status WHERE {
  ?card <http://cardgames.org/schema#artist> ?artist .
  OPTIONAL {
    ?artist rdfs:label ?artistLabel .
  }
  FILTER ( ( isLiteral( ?artist ) && contains( LCASE( STR( ?artist ) ) , "allen williams" ) ) || ( ! isLiteral( ?artist ) && bound( ?artistLabel ) && contains( LCASE( STR( ?artistLabel ) ) , "allen williams" ) ) ) OPTIONAL {
    ?card <http://cardgames.org/schema#frameVersion> ?frameVersion .
  }
  OPTIONAL {
    ?card <http://cardgames.org/schema#status> ?status .
  }
  OPTIONAL {
    ?card rdfs:label ?cardLabel .
  }
}
ORDER BY ?cardLabel

PREFIX tox: <http://toxkg.org/schema#>
SELECT ( AVG( ?oCount ) AS ?avgOxygenPerSingleBondedMolecule ) WHERE {
  {
    SELECT ?molecule ( COUNT( DISTINCT ?atom ) AS ?oCount ) WHERE {
      ?atom tox:partOfMolecule ?molecule ; tox:element "Oxygen" .
      FILTER NOT EXISTS {
        ?bond tox:partOfMolecule ?molecule ; tox:bondType ?bt .
        FILTER ( ?bt != "-" )
      }
    }
    GROUP BY ?molecule
  }
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( AVG( ?ratio ) AS ?avg_single_per_atom ) WHERE {
  {
    SELECT ?mol ( COUNT( DISTINCT ?bond ) AS ?singleCount ) ( COUNT( DISTINCT ?atom ) AS ?atomCount ) WHERE {
      ?mol tox:hasCarcinogenicity "Carcinogenic" .
      ?atom tox:partOfMolecule ?mol .
      OPTIONAL {
        ?bond tox:connectsAtom ?atom .
        ?bond tox:bondType "-" .
      }
    }
    GROUP BY ?mol
  }
  BIND( IF( ?atomCount > 0 , xsd:decimal ( ?singleCount ) / xsd:decimal ( ?atomCount ) , 0 ) AS ?ratio )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT DISTINCT ?molecule ?moleculeLabel WHERE {
  ?bond a tox:Bond .
  ?bond tox:bondType "#" .
  ?bond tox:partOfMolecule ?molecule .
  ?molecule tox:hasCarcinogenicity "Carcinogenic" .
  OPTIONAL {
    ?molecule rdfs:label ?moleculeLabel
  }
}
ORDER BY ?molecule

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?carbons ?total ( ( xsd:double ( ?carbons ) / xsd:double ( ?total ) ) AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( ?atom ) AS ?total ) WHERE {
      ?bond a tox:Bond ; tox:bondType "=" ; tox:partOfMolecule ?mol .
      ?atom tox:partOfMolecule ?mol .
    }
  }
  {
    SELECT ( COUNT( ?carbonAtom ) AS ?carbons ) WHERE {
      ?bond2 a tox:Bond ; tox:bondType "=" ; tox:partOfMolecule ?mol2 .
      ?carbonAtom tox:partOfMolecule ?mol2 ; tox:element ?el .
      FILTER ( lcase( str( ?el ) ) = "carbon" )
    }
  }
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?bond ?atom ?element WHERE {
  BIND( <http://toxkg.org/bond/TR004_8_9> AS ?bond ) ?bond a tox:Bond ; tox:connectsAtom ?atom .
  ?atom tox:element ?element .
}
ORDER BY ?atom

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?bond ?bondType WHERE {
  BIND( <http://toxkg.org/atom/TR004_8> AS ?a ) BIND( <http://toxkg.org/atom/TR004_20> AS ?b ) ?bond tox:connectsAtom ?a .
  ?bond tox:connectsAtom ?b .
  OPTIONAL {
    ?bond tox:bondType ?bondType
  }
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?code ( COUNT( DISTINCT ?atom ) AS ?count ) WHERE {
  VALUES ?code {
    "i" "s"
  }
  ?bond a tox:Bond ; tox:bondType "-" ; tox:connectsAtom ?atom .
  ?atom tox:element ?elem .
  BIND( lcase( str( ?elem ) ) AS ?el ) FILTER ( ( ?code = "i" && ( ?el = "i" || ?el = "iodine" ) ) || ( ?code = "s" && ( ?el = "s" || ?el = "sulfur" ) ) )
}
GROUP BY ?code
ORDER BY ?code

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?total ?withF ?withoutF ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?mol ) AS ?total ) WHERE {
      ?mol tox:hasCarcinogenicity "Carcinogenic" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?molWithF ) AS ?withF ) WHERE {
      ?molWithF tox:hasCarcinogenicity "Carcinogenic" .
      ?atom tox:partOfMolecule ?molWithF ; tox:element "Fluorine" .
    }
  }
  BIND( ( ?total - ?withF ) AS ?withoutF ) BIND( ( ( ?withoutF * 100.0 ) / ?total ) AS ?percentage )
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ( ( SUM( IF( str( ?bondType ) = "#" , 1 , 0 ) ) * 100.0 ) / COUNT( ?bond ) AS ?percent ) ( COUNT( ?bond ) AS ?totalBonds ) ( SUM( IF( str( ?bondType ) = "#" , 1 , 0 ) ) AS ?tripleBonds ) WHERE {
  ?bond a tox:Bond ; tox:partOfMolecule ?mol ; tox:bondType ?bondType .
  ?mol tox:hasCarcinogenicity "Carcinogenic" .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?toxElement ?label WHERE {
  BIND( <http://toxkg.org/molecule/TR000> AS ?molecule ) ?molecule ?p ?toxElement .
  FILTER ( STRSTARTS( STR( ?p ) , STR( tox: ) ) ) .
  OPTIONAL {
    ?toxElement rdfs:label ?toxElementLabel .
  }
  BIND( COALESCE ( STR( ?toxElementLabel ) , STR( ?toxElement ) ) AS ?label )
}
ORDER BY LCASE( ?label )
LIMIT 3

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?percentStr ?total ?doubleCount WHERE {
  {
    SELECT ( COUNT( ?bond ) AS ?total ) ( SUM( IF( ?bondType = "=" , 1 , 0 ) ) AS ?doubleCount ) WHERE {
      ?bond tox:partOfMolecule <http://toxkg.org/molecule/TR008> .
      ?bond tox:bondType ?bondType .
    }
  }
  BIND( IF( ?total = 0 , 0 , ( xsd:decimal ( ?doubleCount ) / xsd:decimal ( ?total ) ) * 100 ) AS ?rawPercent ) BIND( xsd:integer ( ROUND( ?rawPercent * 100000 ) ) AS ?roundedInt ) BIND( xsd:integer ( FLOOR( xsd:decimal ( ?roundedInt ) / 100000 ) ) AS ?intPart ) BIND( xsd:integer ( xsd:decimal ( ?roundedInt ) - ( ?intPart * 100000 ) ) AS ?frac ) BIND( STR( ?frac ) AS ?fracStr ) BIND( xsd:integer ( 5 - STRLEN( ?fracStr ) ) AS ?padLen ) BIND( SUBSTR( "00000" , 1 , ?padLen ) AS ?pad ) BIND( CONCAT ( STR( ?intPart ) , "." , CONCAT ( ?pad , ?fracStr ) ) AS ?percentStr )
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?percent WHERE {
  {
    SELECT ( COUNT( ?m ) AS ?total ) WHERE {
      ?m a tox:Molecule .
    }
  }
  {
    SELECT ( COUNT( ?mc ) AS ?car ) WHERE {
      ?mc a tox:Molecule ; tox:hasCarcinogenicity "Carcinogenic" .
    }
  }
  BIND( ( xsd:decimal ( ?car ) / xsd:decimal ( ?total ) ) * 100.0 AS ?rawPercent ) BIND( ( ROUND( ?rawPercent * 1000 ) / 1000 ) AS ?percent )
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?molecule ?total ?hydrogen ?percentStr WHERE {
  BIND( <http://toxkg.org/molecule/TR206> AS ?molecule ) {
    SELECT ( COUNT( ?atom ) AS ?total ) WHERE {
      ?atom tox:partOfMolecule ?molecule .
    }
  }
  {
    SELECT ( COUNT( ?hAtom ) AS ?hydrogen ) WHERE {
      ?hAtom tox:partOfMolecule ?molecule ; tox:element ?el .
      FILTER ( lcase( str( ?el ) ) = "hydrogen" || lcase( str( ?el ) ) = "h" )
    }
  }
  BIND( ( xsd:decimal ( ?hydrogen ) * 100.0 ) / xsd:decimal ( ?total ) AS ?rawPercent ) BIND( xsd:integer ( ROUND( ?rawPercent * 10000 ) ) AS ?scaled ) BIND( xsd:integer ( ?scaled / 10000 ) AS ?intPart ) BIND( xsd:integer ( ?scaled - ( ?intPart * 10000 ) ) AS ?fracPart ) BIND( STR( ?fracPart ) AS ?fracStr ) BIND( CONCAT ( IF( STRLEN( ?fracStr ) = 4 , "" , IF( STRLEN( ?fracStr ) = 3 , "0" , IF( STRLEN( ?fracStr ) = 2 , "00" , IF( STRLEN( ?fracStr ) = 1 , "000" , "" ) ) ) ) , ?fracStr ) AS ?fracPad ) BIND( CONCAT ( STR( ?intPart ) , "." , ?fracPad ) AS ?percentStr )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?prop ?propLabel ?obj WHERE {
  BIND( <http://toxkg.org/molecule/TR060> AS ?m ) ?m ?prop ?obj .
  FILTER ( STRSTARTS( STR( ?prop ) , STR( tox: ) ) || ?prop = rdfs:label ) OPTIONAL {
    ?prop rdfs:label ?propLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?bondType ( COUNT( ?bond ) AS ?count ) ?carcinogenicity ?bondTypeLabel WHERE {
  <http://toxkg.org/molecule/TR010> tox:hasCarcinogenicity ?carcinogenicity .
  ?bond tox:partOfMolecule <http://toxkg.org/molecule/TR010> ; tox:bondType ?bondType .
  OPTIONAL {
    ?bondType rdfs:label ?bondTypeLabel
  }
}
GROUP BY ?bondType ?carcinogenicity ?bondTypeLabel
ORDER BY DESC ( ?count )
LIMIT 1

PREFIX tox: <http://toxkg.org/schema#>
SELECT ( COUNT( DISTINCT ?bond ) AS ?bondCount ) ?molecule ?atom WHERE {
  BIND( <http://toxkg.org/molecule/TR009> AS ?molecule ) BIND( <http://toxkg.org/atom/TR009_12> AS ?atom ) ?bond tox:connectsAtom ?atom ; tox:partOfMolecule ?molecule .
}
GROUP BY ?molecule ?atom

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?bond ?bondType ?atom1 ?atom2 WHERE {
  BIND( <http://toxkg.org/bond/TR001_6_9> AS ?bond ) OPTIONAL {
    ?bond tox:bondType ?bondType .
  }
  ?bond tox:connectsAtom ?atom1 .
  ?bond tox:connectsAtom ?atom2 .
  FILTER ( ?atom1 != ?atom2 ) FILTER ( str( ?atom1 ) < str( ?atom2 ) )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?atom ( COUNT( DISTINCT ?bond ) AS ?connections ) ?atomLabel WHERE {
  ?bond tox:connectsAtom ?atom .
  FILTER ( regex( str( ?atom ) , "_19$" ) ) OPTIONAL {
    ?atom rdfs:label ?atomLabel
  }
}
GROUP BY ?atom ?atomLabel
ORDER BY DESC ( ?connections )

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?p ?o ?o_label WHERE {
  <http://toxkg.org/molecule/TR004> ?p ?o .
  FILTER ( STRSTARTS( STR( ?p ) , STR( tox: ) ) ) OPTIONAL {
    ?o rdfs:label ?o_label
  }
}
ORDER BY ?p

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT DISTINCT ?molecule ?moleculeLabel WHERE {
  ?atom a tox:Atom ; tox:partOfMolecule ?molecule .
  OPTIONAL {
    ?molecule tox:hasCarcinogenicity ?carcin .
  }
  BIND( STRAFTER( STR( ?atom ) , "/atom/" ) AS ?atomId ) BIND( SUBSTR( ?atomId , 7 , 2 ) AS ?two ) FILTER ( ?two >= "21" && ?two <= "25" ) FILTER ( ?carcin = "Carcinogenic" || ?carcin = "+" ) OPTIONAL {
    ?molecule rdfs:label ?moleculeLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT DISTINCT ?bond ?bondLabel WHERE {
  ?bond a tox:Bond .
  ?bond tox:connectsAtom ?a1 .
  ?bond tox:connectsAtom ?a2 .
  FILTER ( ?a1 != ?a2 ) OPTIONAL {
    ?a1 tox:element ?e1
  }
  OPTIONAL {
    ?a2 tox:element ?e2
  }
  OPTIONAL {
    ?a1 rdfs:label ?l1
  }
  OPTIONAL {
    ?a2 rdfs:label ?l2
  }
  FILTER ( ( ( BOUND( ?e1 ) && LCASE( STR( ?e1 ) ) = "p" ) || ( BOUND( ?l1 ) && CONTAINS( LCASE( STR( ?l1 ) ) , "phosphor" ) ) ) && ( ( BOUND( ?e2 ) && LCASE( STR( ?e2 ) ) = "n" ) || ( BOUND( ?l2 ) && CONTAINS( LCASE( STR( ?l2 ) ) , "nitro" ) ) ) ) OPTIONAL {
    ?bond rdfs:label ?bondLabel
  }
}

PREFIX tox: <http://toxkg.org/schema#>
ASK WHERE {
  {
    SELECT ( MAX( ?c ) AS ?max ) WHERE {
      SELECT ?m ( COUNT( DISTINCT ?b ) AS ?c ) WHERE {
        ?b tox:bondType "=" ; tox:connectsAtom ?a .
        ?a tox:partOfMolecule ?m .
      }
      GROUP BY ?m
    }
  }
  FILTER NOT EXISTS {
    {
      SELECT ?m2 ( COUNT( DISTINCT ?b2 ) AS ?count2 ) WHERE {
        ?b2 tox:bondType "=" ; tox:connectsAtom ?a2 .
        ?a2 tox:partOfMolecule ?m2 .
      }
      GROUP BY ?m2
    }
    FILTER ( ?count2 = ?max ) ?m2 tox:hasCarcinogenicity ?carc2 .
    FILTER ( ?carc2 != "Carcinogenic" )
  }
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( xsd:decimal ( COUNT( ?bond ) ) / xsd:decimal ( COUNT( DISTINCT ?atom ) ) AS ?average ) WHERE {
  ?bond tox:connectsAtom ?atom .
  ?atom tox:element "Iodine" .
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT DISTINCT ?element WHERE {
  ?atom rdf:type tox:Atom .
  ?atom tox:element ?element .
  FILTER NOT EXISTS {
    ?bond tox:connectsAtom ?atom
  }
}
ORDER BY ?element

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?bond ?bondLabel ?atom1 ?atom1Label ?atom2 ?atom2Label WHERE {
  ?bond tox:partOfMolecule <http://toxkg.org/molecule/TR041> ; tox:bondType "#" ; tox:connectsAtom ?atom1 , ?atom2 .
  FILTER ( ?atom1 < ?atom2 ) OPTIONAL {
    ?bond rdfs:label ?bondLabel
  }
  OPTIONAL {
    ?atom1 rdfs:label ?atom1Label
  }
  OPTIONAL {
    ?atom2 rdfs:label ?atom2Label
  }
}
ORDER BY ?bond

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?atom ?element ?atomLabel WHERE {
  <http://toxkg.org/bond/TR144_8_19> tox:connectsAtom ?atom .
  ?atom tox:element ?element .
  OPTIONAL {
    ?atom rdfs:label ?atomLabel
  }
}
ORDER BY ?atom

PREFIX tox: <http://toxkg.org/schema#>
SELECT DISTINCT ?element ?bond ?atom WHERE {
  ?bond tox:bondType "#" .
  ?bond tox:connectsAtom ?atom .
  ?atom tox:element ?element .
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?total ?carc ?percent ?scaled ?percent_5dp_str WHERE {
  {
    SELECT ( COUNT( ?bond ) AS ?total ) WHERE {
      ?bond a tox:Bond ; tox:bondType "-" .
    }
  }
  {
    SELECT ( COUNT( ?bond2 ) AS ?carc ) WHERE {
      ?bond2 a tox:Bond ; tox:bondType "-" ; tox:partOfMolecule ?mol .
      ?mol tox:hasCarcinogenicity "Carcinogenic" .
    }
  }
  BIND( ( ?carc * 100.0 ) / ?total AS ?percent ) BIND( ROUND( ?percent * 100000.0 ) AS ?scaled ) BIND( FLOOR( ?scaled / 100000 ) AS ?intPart ) BIND( ( ?scaled - ( ?intPart * 100000 ) ) AS ?fracInt ) BIND( STR( ?fracInt ) AS ?fracStr ) BIND( STRLEN( ?fracStr ) AS ?flen ) BIND( IF( ?flen < 5 , SUBSTR( "00000" , 1 , ( 5 - ?flen ) ) , "" ) AS ?pad ) BIND( CONCAT ( STR( ?intPart ) , "." , ?pad , ?fracStr ) AS ?percent_5dp_str )
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ( SUM( ?atomCount ) AS ?totalAtoms ) WHERE {
  {
    SELECT ?mol ( COUNT( DISTINCT ?atom ) AS ?atomCount ) WHERE {
      ?b tox:partOfMolecule ?mol ; tox:bondType "#" .
      ?a1 tox:partOfMolecule ?mol ; tox:element ?elem .
      FILTER ( ?elem IN ( "Phosphorus" , "Bromine" ) ) ?atom tox:partOfMolecule ?mol .
    }
    GROUP BY ?mol
  }
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ( SUM( IF( str( ?element ) = "Chlorine" , 1 , 0 ) ) AS ?num_chlorine ) ( COUNT( ?atom ) AS ?total_atoms ) ( ( SUM( IF( str( ?element ) = "Chlorine" , 1 , 0 ) ) / COUNT( ?atom ) ) * 100 AS ?percent ) WHERE {
  ?bond tox:bondType "-" .
  ?bond tox:connectsAtom ?atom .
  ?atom tox:element ?element .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?bond ?atom ?atomLabel ?element WHERE {
  BIND( <http://toxkg.org/bond/TR001_10_11> AS ?bond ) ?bond tox:connectsAtom ?atom .
  OPTIONAL {
    ?atom rdfs:label ?atomLabel
  }
  ?atom tox:element ?element .
}
ORDER BY ?atom

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX tox: <http://toxkg.org/schema#>
SELECT ?percentage ?withCl ?total WHERE {
  {
    SELECT ( COUNT( DISTINCT ?m ) AS ?total ) WHERE {
      ?m rdf:type tox:Molecule ; tox:hasCarcinogenicity "Carcinogenic" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?m2 ) AS ?withCl ) WHERE {
      ?m2 rdf:type tox:Molecule ; tox:hasCarcinogenicity "Carcinogenic" .
      ?a tox:partOfMolecule ?m2 ; tox:element "Chlorine" .
    }
  }
  BIND( ( ( ?withCl * 100.0 ) / ?total ) AS ?percentage )
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?molecule ( ( xsd:decimal ( SUM( ?isH ) ) / xsd:decimal ( COUNT( ?element ) ) ) AS ?ratio ) ( IF( CONTAINS( LCASE( STR( ?carc ) ) , "carcinog" ) , "+" , "-" ) AS ?label ) ( SUM( ?isH ) AS ?hydrogen_count ) ( COUNT( ?element ) AS ?total_count ) WHERE {
  BIND( <http://toxkg.org/molecule/TR006> AS ?molecule ) OPTIONAL {
    ?molecule tox:hasCarcinogenicity ?carc .
  }
  ?atom a tox:Atom ; tox:partOfMolecule ?molecule ; tox:element ?element .
  BIND( IF( LCASE( STR( ?element ) ) IN ( "h" , "hydrogen" ) , 1 , 0 ) AS ?isH )
}
GROUP BY ?molecule ?carc

PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?frpm ?schoolEntity ?schoolName ?street ?city ?state ?zip ?enrollK12 ?enrollAges ?diff WHERE {
  ?frpm cs:enrollmentK12 ?enrollK12 ; cs:enrollmentAges5_17 ?enrollAges ; cs:schoolName ?schoolName .
  BIND( str( ?frpm ) AS ?frpmStr ) BIND( strafter( ?frpmStr , "/frpm/" ) AS ?after ) BIND( strbefore( ?after , "/" ) AS ?cds ) BIND( IRI( CONCAT ( "http://calischools.org/school/" , ?cds ) ) AS ?schoolEntity ) OPTIONAL {
    ?schoolEntity cs:street ?street .
  }
  OPTIONAL {
    ?schoolEntity cs:city ?city .
  }
  OPTIONAL {
    ?schoolEntity cs:state ?state .
  }
  OPTIONAL {
    ?schoolEntity cs:zip ?zip .
  }
  BIND( ( xsd:integer ( ?enrollK12 ) - xsd:integer ( ?enrollAges ) ) AS ?diff ) FILTER ( ?diff > 30 )
}
ORDER BY DESC ( ?diff )

PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school ?schoolName ?freeMealCountK12 ?enrollmentK12 ?totalScore ?avgScoreMath ?avgScoreReading ?avgScoreWriting ?numTestTakers WHERE {
  ?school cs:freeMealCountK12 ?freeMealCountK12 .
  ?school cs:enrollmentK12 ?enrollmentK12 .
  OPTIONAL {
    ?school cs:avgScoreMath ?avgScoreMath
  }
  OPTIONAL {
    ?school cs:avgScoreReading ?avgScoreReading
  }
  OPTIONAL {
    ?school cs:avgScoreWriting ?avgScoreWriting
  }
  OPTIONAL {
    ?school cs:schoolName ?schoolName
  }
  OPTIONAL {
    ?school cs:numTestTakers ?numTestTakers
  }
  FILTER ( ?enrollmentK12 > 0 ) FILTER ( bound( ?avgScoreMath ) || bound( ?avgScoreReading ) || bound( ?avgScoreWriting ) ) BIND( ( COALESCE ( xsd:decimal ( ?avgScoreMath ) , 0 ) + COALESCE ( xsd:decimal ( ?avgScoreReading ) , 0 ) + COALESCE ( xsd:decimal ( ?avgScoreWriting ) , 0 ) ) AS ?totalScore ) FILTER ( ( ?freeMealCountK12 / ?enrollmentK12 ) > 0.1 ) FILTER ( ?totalScore >= 1500 ) FILTER ( ! bound( ?numTestTakers ) || xsd:decimal ( ?numTestTakers ) > 0 )
}
ORDER BY ?schoolName

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?label ?fund WHERE {
  ?school a cs:School ; cs:city ?city .
  FILTER ( LCASE( STR( ?city ) ) = "riverside" ) OPTIONAL {
    ?school rdfs:label ?label
  }
  OPTIONAL {
    ?school cs:fundingType ?fund
  }
}
ORDER BY ?label

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?school ?label ?mailStreet ?mailCity ?mailState ?mailZip ?frpmCount WHERE {
  ?school cs:mailCity ?mailCity .
  FILTER ( lcase( str( ?mailCity ) ) = "monterey" ) .
  ?school cs:gradesServed ?gradesServed .
  FILTER ( str( ?gradesServed ) = "9-12" ) .
  ?school cs:schoolName ?sname .
  ?fr cs:schoolName ?sname ; cs:frpmCountAges5_17 ?frpmCount .
  FILTER ( xsd:integer ( ?frpmCount ) > 800 ) .
  OPTIONAL {
    ?school rdfs:label ?label
  }
  OPTIONAL {
    ?school cs:mailStreet ?mailStreet
  }
  OPTIONAL {
    ?school cs:mailState ?mailState
  }
  OPTIONAL {
    ?school cs:mailZip ?mailZip
  }
}
ORDER BY ?label

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?school ?schoolLabel ?writing ?phone WHERE {
  ?sat cs:avgScoreWriting ?writing .
  BIND( STRAFTER( STR( ?sat ) , "http://calischools.org/sat/" ) AS ?cds ) BIND( IRI( CONCAT ( "http://calischools.org/school/" , ?cds ) ) AS ?school ) OPTIONAL {
    ?school rdfs:label ?schoolLabel
  }
  OPTIONAL {
    ?school cs:phone ?phone
  }
  OPTIONAL {
    ?school cs:openDate ?openDate
  }
  OPTIONAL {
    ?school cs:closedDate ?closedDate
  }
  FILTER ( ( BOUND( ?openDate ) && ?openDate > "1991-12-31" ^^ xsd:date ) || ( BOUND( ?closedDate ) && ?closedDate < "2000-01-01" ^^ xsd:date ) )
}
ORDER BY ?schoolLabel

PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school ?schoolName ?docType WHERE {
  {
    SELECT ( AVG( ?diffsub ) AS ?avgDiff ) WHERE {
      ?s cs:fundingType "Locally funded" ; cs:enrollmentK12 ?k12sub ; cs:enrollmentAges5_17 ?a5sub .
      BIND( xsd:decimal ( ?k12sub ) - xsd:decimal ( ?a5sub ) AS ?diffsub )
    }
  }
  ?school cs:fundingType "Locally funded" ; cs:enrollmentK12 ?k12 ; cs:enrollmentAges5_17 ?a5_17 .
  BIND( xsd:decimal ( ?k12 ) - xsd:decimal ( ?a5_17 ) AS ?diff ) FILTER ( ?diff > ?avgDiff ) OPTIONAL {
    ?school cs:schoolName ?schoolName
  }
  OPTIONAL {
    ?school cs:docType ?docType
  }
}
ORDER BY ?schoolName

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school ?schoolLabel ?frpmCountK12 ?enrollmentK12 ?frpmRate WHERE {
  ?frpm a cs:FRPMRecord ; cs:frpmCountK12 ?frpmCountK12 ; cs:enrollmentK12 ?enrollmentK12 ; cs:lowGrade ?lowGrade ; cs:highGrade ?highGrade .
  FILTER ( ( ?lowGrade = "K" || ?lowGrade = "1" ) && ?highGrade = "12" ) BIND( IRI( REPLACE( STR( ?frpm ) , "^http://calischools.org/frpm/([0-9]+).*$" , "http://calischools.org/school/$1" ) ) AS ?school ) ?school cs:socCode "66" .
  OPTIONAL {
    ?school rdfs:label ?schoolLabel
  }
  FILTER ( xsd:decimal ( ?enrollmentK12 ) > 0 ) BIND( xsd:decimal ( ?frpmCountK12 ) / xsd:decimal ( ?enrollmentK12 ) AS ?frpmRate )
}
ORDER BY DESC ( xsd:decimal ( ?frpmCountK12 ) )
LIMIT 5

PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?streetOut ?cityOut ?stateOut ?zipOut ?numGE1500 ?numTestTakers ?rate WHERE {
  ?school cs:numGE1500 ?numGE1500 ; cs:numTestTakers ?numTestTakers .
  FILTER ( ?numTestTakers > 0 ) BIND( ( ?numGE1500 / ?numTestTakers ) AS ?rate ) OPTIONAL {
    ?school cs:street ?street
  }
  OPTIONAL {
    ?school cs:mailStreet ?mailStreet
  }
  OPTIONAL {
    ?school cs:city ?city
  }
  OPTIONAL {
    ?school cs:mailCity ?mailCity
  }
  OPTIONAL {
    ?school cs:state ?state
  }
  OPTIONAL {
    ?school cs:mailState ?mailState
  }
  OPTIONAL {
    ?school cs:zip ?zip
  }
  OPTIONAL {
    ?school cs:mailZip ?mailZip
  }
  BIND( COALESCE ( ?street , ?mailStreet ) AS ?streetOut ) BIND( COALESCE ( ?city , ?mailCity ) AS ?cityOut ) BIND( COALESCE ( ?state , ?mailState ) AS ?stateOut ) BIND( COALESCE ( ?zip , ?mailZip ) AS ?zipOut )
}
ORDER BY ASC ( ?rate )
LIMIT 1

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX cs: <http://calischools.org/schema#>
SELECT ?admin ?firstName ?lastName WHERE {
  {
    SELECT ?sat WHERE {
      ?sat rdf:type cs:SATScore ; cs:numGE1500 ?num .
    }
    ORDER BY DESC ( ?num )
    LIMIT 1
  }
  ?admin rdf:type cs:Administrator .
  ?admin cs:firstName ?firstName ; cs:lastName ?lastName .
  FILTER ( STRSTARTS( STR( ?admin ) , CONCAT ( "http://calischools.org/admin/" , STRAFTER( STR( ?sat ) , "/sat/" ) ) ) )
}
ORDER BY ?lastName ?firstName

PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( AVG( xsd:decimal ( ?numTestTakers ) ) AS ?avgTestTakers ) ( COUNT( ?school ) AS ?numSchools ) WHERE {
  ?school cs:city ?city ; cs:openDate ?openDate ; cs:numTestTakers ?numTestTakers .
  FILTER ( regex( str( ?city ) , "^Fresno$" , "i" ) ) FILTER ( ?openDate >= "1980-01-01" ^^ xsd:date && ?openDate <= "1980-12-31" ^^ xsd:date )
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?phone ?avg WHERE {
  ?sat cs:districtName "Fresno Unified" ; cs:avgScoreReading ?avg ; cs:schoolName ?sname .
  ?school rdf:type cs:School ; cs:schoolName ?sname .
  OPTIONAL {
    ?school cs:phone ?phone
  }
  {
    SELECT ( MIN( ?avgInner ) AS ?minAvg ) WHERE {
      ?s cs:districtName "Fresno Unified" ; cs:avgScoreReading ?avgInner .
    }
  }
  FILTER ( ?avg = ?minAvg )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?label ?county ?avgReading WHERE {
  ?sat cs:schoolName ?sname ; cs:avgScoreReading ?avgReading ; cs:countyName ?countyName .
  ?school cs:schoolName ?sname ; cs:virtualType "Exclusively Virtual" ; cs:county ?county .
  OPTIONAL {
    ?school rdfs:label ?label
  }
  {
    SELECT ?school ( COUNT( ?otherSchool ) AS ?numBetter ) WHERE {
      ?school cs:schoolName ?sname1 ; cs:virtualType "Exclusively Virtual" ; cs:county ?county .
      ?sat1 cs:schoolName ?sname1 ; cs:avgScoreReading ?avg1 .
      ?otherSchool cs:schoolName ?sname2 ; cs:virtualType "Exclusively Virtual" ; cs:county ?county .
      ?sat2 cs:schoolName ?sname2 ; cs:avgScoreReading ?avg2 .
      FILTER ( ?avg2 > ?avg1 )
    }
    GROUP BY ?school ?avg1 ?county
  }
  FILTER ( ?numBetter < 5 )
}
ORDER BY ?county DESC ( ?avgReading )

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?schoolLabel ?avgWriting WHERE {
  ?admin a cs:Administrator ; rdfs:label "Ricci Ulrich" .
  ?school ?p ?admin .
  OPTIONAL {
    ?school rdfs:label ?schoolLabel
  }
  OPTIONAL {
    ?school cs:avgScoreWriting ?avgWriting
  }
}
LIMIT 200

PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?schoolName ?enroll WHERE {
  {
    SELECT ( MAX( ?enroll ) AS ?maxEnroll ) WHERE {
      ?school a cs:School ; cs:docCode "31" ; cs:cdsCode ?cds .
      ?frpm a cs:FRPMRecord ; cs:enrollmentK12 ?enroll .
      FILTER ( CONTAINS( STR( ?frpm ) , STR( ?cds ) ) )
    }
  }
  ?school a cs:School ; cs:docCode "31" ; cs:cdsCode ?cds .
  OPTIONAL {
    ?school cs:schoolName ?schoolName
  }
  ?frpm a cs:FRPMRecord ; cs:enrollmentK12 ?enroll .
  FILTER ( CONTAINS( STR( ?frpm ) , STR( ?cds ) ) ) FILTER ( ?enroll = ?maxEnroll )
}
ORDER BY ?school

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school ?schoolLabel ?count ?monthlyAverage WHERE {
  {
    SELECT ?school WHERE {
      ?school rdf:type cs:School ; cs:county "Alameda" ; cs:docCode "52" ; cs:openDate ?openDate .
      FILTER ( year( ?openDate ) = 1980 )
    }
  }
  OPTIONAL {
    ?school rdfs:label ?schoolLabel
  }
  {
    SELECT ( COUNT( ?s ) AS ?count ) WHERE {
      ?s rdf:type cs:School ; cs:county "Alameda" ; cs:docCode "52" ; cs:openDate ?od .
      FILTER ( year( ?od ) = 1980 )
    }
  }
  BIND( ( xsd:decimal ( ?count ) / 12 ) AS ?monthlyAverage )
}
ORDER BY ?school

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?label ?schoolName ?mailStreet ?mathAverage WHERE {
  ?sat a cs:SATScore ; cs:avgScoreMath ?mathAverage .
  BIND( IRI( REPLACE( STR( ?sat ) , "sat/" , "school/" ) ) AS ?school ) OPTIONAL {
    ?school rdfs:label ?label .
  }
  OPTIONAL {
    ?school cs:schoolName ?schoolName .
  }
  OPTIONAL {
    ?school cs:mailStreet ?mailStreet .
  }
}
ORDER BY DESC ( ?mathAverage )
OFFSET 6
LIMIT 1

PREFIX cs: <http://calischools.org/schema#>
SELECT ?school ?frpm ?enrollment WHERE {
  ?school a cs:School ; cs:schoolName ?sname ; cs:edOpsCode "SSS" .
  ?frpm a cs:FRPMRecord ; cs:schoolName ?sname ; cs:academicYear "2014-2015" ; cs:enrollmentAges5_17 ?enrollment .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school ?schoolLabel ?gradesServed ?frpmCountAges5_17 ?enrollmentAges5_17 ?percent WHERE {
  ?school cs:countyName ?countyName .
  FILTER ( regex( str( ?countyName ) , "^\\s*Los Angeles\\s*$" , "i" ) ) ?school cs:gradesServed ?gradesServed .
  FILTER ( regex( str( ?gradesServed ) , "^\\s*K\\s*-\\s*9\\s*$" , "i" ) ) ?school cs:frpmCountAges5_17 ?frpmCountAges5_17 .
  ?school cs:enrollmentAges5_17 ?enrollmentAges5_17 .
  BIND( ( xsd:decimal ( ?frpmCountAges5_17 ) / xsd:decimal ( ?enrollmentAges5_17 ) ) * 100 AS ?percent ) OPTIONAL {
    ?school rdfs:label ?schoolLabel
  }
}
ORDER BY DESC ( ?percent )

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school ?label ?gradesOffered ?lowGrade ?highGrade ?lon ?absLon WHERE {
  {
    SELECT ( MAX( ?abs ) AS ?maxAbs ) WHERE {
      ?s cs:longitude ?lon2 .
      BIND( xsd:double ( ?lon2 ) AS ?lonNum2 ) BIND( abs( ?lonNum2 ) AS ?abs )
    }
  }
  ?school cs:longitude ?lon .
  BIND( xsd:double ( ?lon ) AS ?lonNum ) BIND( abs( ?lonNum ) AS ?absLon ) FILTER ( ?absLon = ?maxAbs ) OPTIONAL {
    ?school cs:gradesOffered ?gradesOffered
  }
  OPTIONAL {
    ?school cs:lowGrade ?lowGrade
  }
  OPTIONAL {
    ?school cs:highGrade ?highGrade
  }
  OPTIONAL {
    ?school rdfs:label ?label
  }
}

PREFIX cs: <http://calischools.org/schema#>
SELECT ?magnetMultipleCount ?numCities ?city ( COUNT( DISTINCT ?school ) AS ?cityK8Count ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?s1 ) AS ?magnetMultipleCount ) WHERE {
      ?s1 cs:gradesServed "K-8" .
      ?s1 cs:isMagnet ?isMagnet .
      ?s1 cs:nslpProvisionStatus ?prov .
      FILTER ( STR( ?isMagnet ) = "1" ) .
      FILTER ( STR( ?prov ) = "Multiple Provision Types" ) .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?city2 ) AS ?numCities ) WHERE {
      ?s2 cs:gradesServed "K-8" .
      ?s2 cs:city ?city2 .
    }
  }
  ?school cs:gradesServed "K-8" .
  OPTIONAL {
    ?school cs:city ?city .
  }
}
GROUP BY ?magnetMultipleCount ?numCities ?city
ORDER BY DESC ( ?cityK8Count )

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
SELECT DISTINCT ?school ?schoolLabel ?districtCode ?freeMealCountK12 ?enrollmentK12 ( ( ?freeMealCountK12 / ?enrollmentK12 ) * 100 AS ?percentFreeK12 ) WHERE {
  ?admin cs:firstName "Alusine" .
  {
    ?school cs:administrator ?admin .
  } UNION {
    ?school cs:principal ?admin .
  } UNION {
    ?school cs:firstName "Alusine" .
  } UNION {
    ?school cs:adminName ?adminLabel .
    ?admin rdfs:label ?adminLabel .
  }
  ?school cs:cdsCode ?cds .
  ?frpm ?p ?o .
  FILTER ( CONTAINS( STR( ?frpm ) , CONCAT ( "/" , STR( ?cds ) , "/" ) ) ) ?frpm cs:freeMealCountK12 ?freeMealCountK12 .
  ?frpm cs:enrollmentK12 ?enrollmentK12 .
  OPTIONAL {
    ?frpm cs:districtCode ?districtCode
  }
  OPTIONAL {
    ?school rdfs:label ?schoolLabel
  }
  FILTER ( ?enrollmentK12 > 0 )
}
LIMIT 50

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX cs: <http://calischools.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?school ?cds ?label ?openDate ?email ?admin WHERE {
  ?school cs:county ?county ; cs:city ?city ; cs:districtName "San Bernardino City Unified" ; cs:openDate ?openDate ; cs:socCode ?soc ; cs:docCode ?doc ; cs:cdsCode ?cds .
  OPTIONAL {
    ?school rdfs:label ?label
  }
  FILTER ( xsd:date ( str( ?openDate ) ) >= "2009-01-01" ^^ xsd:date && xsd:date ( str( ?openDate ) ) <= "2010-12-31" ^^ xsd:date ) FILTER ( str( ?soc ) = "62" || str( ?soc ) = "62.0" ) FILTER ( str( ?doc ) = "54" || str( ?doc ) = "54.0" ) ?admin ?p ?o .
  FILTER ( regex( str( ?admin ) , CONCAT ( "^http://calischools.org/admin/" , STR( ?cds ) ) ) ) ?admin cs:email ?email .
  FILTER ( regex( str( ?email ) , "^[^@\\s]+@[^@\\s]+\\.[^@\\s]+$" , "i" ) )
}
ORDER BY ?label

PREFIX fin: <http://financialdb.org/schema#>
SELECT ( COUNT( DISTINCT ?account ) AS ?count ) WHERE {
  ?account a fin:Account ; fin:belongsToDistrict ?district ; fin:frequencyRaw ?freqRaw .
  ?district fin:region ?region .
  FILTER ( LCASE( STR( ?freqRaw ) ) = "poplatek po obratu" ) FILTER ( LCASE( STR( ?region ) ) = "east bohemia" )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ( COUNT( DISTINCT ?district ) AS ?count ) WHERE {
  {
    ?district fin:averageSalaryFemale ?avg .
  } UNION {
    ?obs fin:averageSalary ?avg ; fin:gender "Female" ; fin:belongsToDistrict ?district .
  } UNION {
    ?district fin:averageSalary ?avg ; fin:gender "Female" .
  }
  FILTER ( xsd:decimal ( ?avg ) > 6000 && xsd:decimal ( ?avg ) < 10000 )
}

PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?account ?accountId ?client ?clientBirthDate ?minAvg ?maxAvg ( ?maxAvg - ?minAvg AS ?gap ) WHERE {
  BIND( 8110 AS ?minAvg ) BIND( 12541 AS ?maxAvg ) ?district fin:averageSalary ?districtAvg .
  FILTER ( ?districtAvg = ?minAvg ) ?client fin:livesInDistrict ?district ; fin:gender ?gender ; fin:birthDate ?clientBirthDate .
  FILTER ( ?gender = "Female" || ?gender = "F" ) {
    SELECT ( MIN( ?bd ) AS ?minBD ) WHERE {
      ?c fin:livesInDistrict ?d ; fin:gender ?g ; fin:birthDate ?bd .
      ?d fin:averageSalary ?ad .
      FILTER ( ?ad = 8110 ) FILTER ( ?g = "Female" || ?g = "F" )
    }
  }
  FILTER ( ?clientBirthDate = ?minBD ) ?disp fin:forClient ?client ; fin:forAccount ?account .
  ?account fin:accountId ?accountId .
}
ORDER BY ?accountId

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?account ?accountId ?client ?clientLabel ?district ?districtLabel WHERE {
  {
    SELECT ( MAX( ?avg ) AS ?maxAvg ) WHERE {
      ?d fin:averageSalary ?avg .
    }
  }
  {
    SELECT ?district ( MAX( ?bd ) AS ?maxBDinDistrict ) WHERE {
      ?c a fin:Client ; fin:livesInDistrict ?district ; fin:birthDate ?bd .
    }
    GROUP BY ?district
  }
  ?district fin:averageSalary ?avg .
  FILTER ( ?avg = ?maxAvg ) ?client a fin:Client ; fin:livesInDistrict ?district ; fin:birthDate ?bd .
  FILTER ( ?bd = ?maxBDinDistrict ) ?disp a fin:Disposition ; fin:forClient ?client ; fin:forAccount ?account .
  OPTIONAL {
    ?account fin:accountId ?accountId .
  }
  OPTIONAL {
    ?client rdfs:label ?clientLabel .
  }
  OPTIONAL {
    ?district rdfs:label ?districtLabel .
  }
}
ORDER BY ?account

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?account ?accountLabel ?loanTx ?loanAmount WHERE {
  ?loanTx a fin:Transaction ; fin:transactionDate ?tdate ; fin:transactionPurposeLabel ?purpose ; fin:transactionAmount ?loanAmount ; fin:forAccount ?account .
  FILTER ( STRSTARTS( STR( ?tdate ) , "1997" ) && CONTAINS( UCASE( STR( ?purpose ) ) , "LOAN" ) ) ?feeTx a fin:Transaction ; fin:forAccount ?account ; ?feePurposeProp ?feePurpose .
  FILTER ( CONTAINS( UCASE( STR( ?feePurpose ) ) , "POPLATEK" ) && CONTAINS( UCASE( STR( ?feePurpose ) ) , "TYDNE" ) ) {
    SELECT ( MIN( ?loanAmountInner ) AS ?minAmount ) WHERE {
      ?tInner a fin:Transaction ; fin:transactionDate ?dInner ; fin:transactionPurposeLabel ?pInner ; fin:transactionAmount ?loanAmountInner .
      FILTER ( STRSTARTS( STR( ?dInner ) , "1997" ) && CONTAINS( UCASE( STR( ?pInner ) ) , "LOAN" ) )
    }
  }
  FILTER ( ?loanAmount = ?minAmount ) OPTIONAL {
    ?account rdfs:label ?accountLabel
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?account ?accountLabel ?loan ?loanAmount WHERE {
  ?loan a fin:Loan ; fin:loanAmount ?loanAmount ; fin:loanDuration ?loanDuration ; fin:belongsToAccount ?account .
  ?account fin:createdOn ?createdOn .
  FILTER ( ?loanDuration > 12 ) .
  FILTER ( STRSTARTS( STR( ?createdOn ) , "1993" ) ) .
  {
    SELECT ( MAX( ?loanAmt ) AS ?maxAmount ) WHERE {
      ?ln a fin:Loan ; fin:loanAmount ?loanAmt ; fin:loanDuration ?loanDuration2 ; fin:belongsToAccount ?acc2 .
      ?acc2 fin:createdOn ?createdOn2 .
      FILTER ( ?loanDuration2 > 12 ) .
      FILTER ( STRSTARTS( STR( ?createdOn2 ) , "1993" ) ) .
    }
  }
  FILTER ( ?loanAmount = ?maxAmount ) .
  OPTIONAL {
    ?account rdfs:label ?accountLabel
  }
}
ORDER BY ?account

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?client ?clientLabel ?district ?districtLabel WHERE {
  ?client a fin:Client ; fin:birthDate "1976-01-29" ^^ xsd:date ; fin:gender ?g .
  FILTER ( str( ?g ) = "Female" || str( ?g ) = "F" || str( ?g ) = "female" || str( ?g ) = "f" ) ?disp a fin:Disposition ; fin:forClient ?client ; fin:forAccount ?acc .
  ?acc fin:belongsToDistrict ?district .
  OPTIONAL {
    ?client rdfs:label ?clientLabel .
  }
  OPTIONAL {
    ?district rdfs:label ?districtLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ?district ?districtLabel ?inh ?maleCount ?totalCount ( ( ?maleCount * 100.0 ) / ?totalCount AS ?percentage ) WHERE {
  {
    SELECT ?district ?inh WHERE {
      ?district a fin:District ; fin:region "south Bohemia" ; fin:inhabitants ?inh .
    }
    ORDER BY DESC ( xsd:integer ( ?inh ) )
    LIMIT 1
  }
  OPTIONAL {
    ?district rdfs:label ?districtLabel
  }
  {
    SELECT ( COUNT( ?cm ) AS ?maleCount ) WHERE {
      ?cm a fin:Client ; fin:livesInDistrict ?district ; fin:gender "Male" .
    }
  }
  {
    SELECT ( COUNT( ?c ) AS ?totalCount ) WHERE {
      ?c a fin:Client ; fin:livesInDistrict ?district .
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?client ?acct ?balStart ?balEnd ( ( ( ?balEnd - ?balStart ) / ?balStart ) * 100.0 AS ?increaseRate ) WHERE {
  {
    SELECT ( MIN( ?date ) AS ?minDate ) WHERE {
      ?t fin:transactionPurposeRaw "UVER" ; fin:transactionDate ?date .
    }
  }
  ?t0 fin:transactionPurposeRaw "UVER" ; fin:transactionDate ?minDate ; fin:forAccount ?acct .
  ?disp fin:forAccount ?acct ; fin:forClient ?client .
  OPTIONAL {
    SELECT ?acct ( SAMPLE( ?bal1 ) AS ?balStart ) WHERE {
      ?tr1 fin:forAccount ?acct ; fin:transactionDate "1993-03-22" ^^ xsd:date ; fin:balanceAfter ?bal1 .
    }
    GROUP BY ?acct
  }
  OPTIONAL {
    SELECT ?acct ( SAMPLE( ?bal2 ) AS ?balEnd ) WHERE {
      ?tr2 fin:forAccount ?acct ; fin:transactionDate "1998-12-27" ^^ xsd:date ; fin:balanceAfter ?bal2 .
    }
    GROUP BY ?acct
  }
  FILTER ( bound( ?balStart ) && bound( ?balEnd ) && ( ?balStart != 0 ) )
}
LIMIT 10

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ?sumA ?total ?percentage WHERE {
  {
    SELECT ( SUM( xsd:decimal ( ?amtA ) ) AS ?sumA ) WHERE {
      ?loanA rdf:type fin:Loan ; fin:status "A" ; fin:loanAmount ?amtA .
    }
  }
  {
    SELECT ( SUM( xsd:decimal ( ?amtAll ) ) AS ?total ) WHERE {
      ?loanAll rdf:type fin:Loan ; fin:loanAmount ?amtAll .
    }
  }
  BIND( ( ( ?sumA ) / ?total ) * 100 AS ?percentage )
}

PREFIX fin: <http://financialdb.org/schema#>
SELECT ?total ?condTotal ?percentage WHERE {
  {
    SELECT ( SUM( ?loanAmount ) AS ?total ) ( SUM( IF( ?status = "C" , ?loanAmount , 0 ) ) AS ?condTotal ) WHERE {
      ?loan fin:loanAmount ?loanAmount ; fin:status ?status .
      FILTER ( ?loanAmount < 100000 )
    }
  }
  BIND( IF( ?total = 0 , 0 , ( ?condTotal / ?total ) * 100 ) AS ?percentage )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?district ?districtLabel ?state ?u1995 ?u1996 ?pctIncrease WHERE {
  ?loan a fin:Loan ; fin:status "D" ; fin:belongsToAccount ?acc .
  ?disp fin:forAccount ?acc ; fin:forClient ?client .
  ?client fin:livesInDistrict ?district .
  ?district fin:unemploymentRate1995 ?u1995 ; fin:unemploymentRate1996 ?u1996 .
  BIND( ( ( xsd:decimal ( ?u1996 ) - xsd:decimal ( ?u1995 ) ) / xsd:decimal ( ?u1995 ) ) * 100 AS ?pctIncrease ) .
  OPTIONAL {
    ?district rdfs:label ?districtLabel
  }
  .
  OPTIONAL {
    ?district fin:region ?state
  }
  .
}
ORDER BY ?districtLabel

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ?district ( COUNT( DISTINCT ?client ) AS ?femaleCount ) ?districtLabel WHERE {
  ?client a fin:Client ; fin:gender "Female" ; fin:livesInDistrict ?district .
  ?disp a fin:Disposition ; fin:forClient ?client ; fin:forAccount ?account .
  OPTIONAL {
    ?district rdfs:label ?districtLabel
  }
}
GROUP BY ?district ?districtLabel
ORDER BY DESC ( ?femaleCount )
LIMIT 9

PREFIX fin: <http://financialdb.org/schema#>
SELECT ?district ( COUNT( ?maleClient ) AS ?maleCount ) WHERE {
  {
    SELECT ?district WHERE {
      ?district fin:crimeRate1995 ?crimeVal .
    }
    ORDER BY DESC ( ?crimeVal )
    LIMIT 1
    OFFSET 1
  }
  OPTIONAL {
    ?maleClient fin:gender "Male" .
    ?maleClient fin:livesInDistrict ?district .
  }
}
GROUP BY ?district

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?client ?clientId ?clientLabel WHERE {
  {
    SELECT ( AVG( ?amt ) AS ?avg ) WHERE {
      ?t a fin:Transaction ; fin:operationModeRaw "VYBER KARTOU" ; fin:transactionDate ?date ; fin:transactionAmount ?amt .
      FILTER ( year( ?date ) = 1998 )
    }
  }
  ?t a fin:Transaction ; fin:operationModeRaw "VYBER KARTOU" ; fin:transactionDate ?date ; fin:transactionAmount ?amt ; fin:forAccount ?acc .
  FILTER ( year( ?date ) = 1998 ) ?disp a fin:Disposition ; fin:forAccount ?acc ; fin:forClient ?client .
  FILTER ( ?amt < ?avg ) OPTIONAL {
    ?client rdfs:label ?clientLabel
  }
  BIND( STRAFTER( STR( ?client ) , "/client/" ) AS ?clientId )
}
ORDER BY ?clientId

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ( AVG( ?avgCrime ) AS ?A15 ) WHERE {
  {
    SELECT ?region ( AVG( ?crime ) AS ?avgCrime ) WHERE {
      ?district fin:region ?region ; fin:crimeRate1995 ?crime .
    }
    GROUP BY ?region
  }
  FILTER ( ?avgCrime > 4000 ) FILTER EXISTS {
    ?acc fin:belongsToDistrict ?districtAcc ; fin:createdOn ?openedDate .
    ?districtAcc fin:region ?region .
    FILTER ( ?openedDate >= "1997-01-01" ^^ xsd:date )
  }
}

PREFIX fin: <http://financialdb.org/schema#>
SELECT ?tx ?txId ?date ?amount ?opRaw ?opLabel WHERE {
  ?disp fin:forClient <http://financialdb.org/client/3356> ; fin:forAccount ?acc .
  ?tx fin:forAccount ?acc ; fin:operationModeRaw ?opRaw .
  FILTER ( str( ?opRaw ) = "VYBER" ) OPTIONAL {
    ?tx fin:operationModeLabel ?opLabel
  }
  OPTIONAL {
    ?tx fin:transactionId ?txId
  }
  OPTIONAL {
    ?tx fin:transactionDate ?date
  }
  OPTIONAL {
    ?tx fin:transactionAmount ?amount
  }
}
ORDER BY ?date ?txId

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ?percentage ?total ?femaleCount WHERE {
  {
    SELECT ( COUNT( DISTINCT ?client ) AS ?total ) ( COUNT( DISTINCT ?femaleClient ) AS ?femaleCount ) WHERE {
      ?disp fin:forClient ?client ; fin:forAccount ?account .
      ?account fin:belongsToDistrict ?district .
      ?district fin:averageSalary ?avg .
      FILTER ( xsd:decimal ( ?avg ) > 10000 ) OPTIONAL {
        ?client fin:gender "F" .
        BIND( ?client AS ?femaleClient )
      }
    }
  }
  BIND( IF( ?total > 0 , ( ( xsd:double ( ?femaleCount ) / xsd:double ( ?total ) ) * 100 ) , 0 ) AS ?percentage )
}

PREFIX fin: <http://financialdb.org/schema#>
SELECT ?account ?statementRequests ?purposeLabel ?count3539 ?sum3539 WHERE {
  BIND( <http://financialdb.org/account/3> AS ?account ) {
    SELECT ( COUNT( ?tx1 ) AS ?statementRequests ) WHERE {
      ?tx1 fin:forAccount ?account ; fin:transactionPurposeLabel "Payment for Statement" .
    }
  }
  OPTIONAL {
    SELECT ?purposeLabel ( COUNT( ?tx ) AS ?count3539 ) ( SUM( ?amt ) AS ?sum3539 ) WHERE {
      ?tx fin:forAccount ?account ; fin:transactionTypeLabel "Withdrawal" ; fin:transactionAmount ?amt ; fin:transactionPurposeLabel ?purposeLabel .
      FILTER ( ?amt = 3539 )
    }
    GROUP BY ?purposeLabel
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ?maleCount ?totalCount ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?client ) AS ?totalCount ) WHERE {
      ?disp fin:forAccount ?acc .
      ?acc fin:frequencyLabel "Weekly" .
      ?disp fin:forClient ?client .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?male ) AS ?maleCount ) WHERE {
      ?disp2 fin:forAccount ?acc2 .
      ?acc2 fin:frequencyLabel "Weekly" .
      ?disp2 fin:forClient ?male .
      ?male fin:gender "Male" .
    }
  }
  BIND( ( xsd:decimal ( ?maleCount ) / xsd:decimal ( ?totalCount ) * 100 ) AS ?percentage )
}

PREFIX fin: <http://financialdb.org/schema#>
SELECT DISTINCT ?account ?accountId WHERE {
  {
    SELECT ( MIN( ?bd ) AS ?minBirth ) WHERE {
      ?c a fin:Client ; fin:gender "Female" ; fin:birthDate ?bd ; fin:livesInDistrict ?d .
      ?d fin:averageSalary 8110 .
    }
  }
  ?client a fin:Client ; fin:gender "Female" ; fin:birthDate ?bd ; fin:livesInDistrict ?d .
  ?d fin:averageSalary 8110 .
  FILTER ( ?bd = ?minBirth ) ?disp a fin:Disposition ; fin:forClient ?client ; fin:forAccount ?account .
  ?account fin:accountId ?accountId .
}
ORDER BY ?accountId
